INSERT INTO tb_article (id, created_by, created_date, created_ip, last_modified_by, last_modified_date, last_modified_ip, version, parent_id, category_id, content, exposed, fixed, fixed_order, thumbnail_id, title, type) VALUES ('cf839b35-96cf-4ac0-ab37-f028c0807642', 'admin', now(), '127.0.0.1', null, null, null, 0, null, '581d25e5-c669-4172-b42d-51831a1f0c4d', '<section class="container-sm my-3"><div style="text-align: center; color: #999999">대전 독서 모임 ''대전 포스트잇'' !!<br>매년 새해가 되면 다이어트와 함께<br>''한 달에 한 권 책 읽기'' 에 도전하는 우리...<br>조그만 포스트잇에 센스 있는 한 줄 평으로<br>시작해보는 건 어떨까요?<br></div></section>', true, true, 2, null, null, 'HTML');
INSERT INTO tb_article (id, created_by, created_date, created_ip, last_modified_by, last_modified_date, last_modified_ip, version, parent_id, category_id, content, exposed, fixed, fixed_order, thumbnail_id, title, type) VALUES ('50d77113-155c-4546-b316-95329aff39b7', 'admin', now(), '127.0.0.1', null, null, null, 0, null, '581d25e5-c669-4172-b42d-51831a1f0c4d', '<section class="container-sm my-3"><div><hr></div></section>', true, true, 3, null, null, 'HTML');
INSERT INTO tb_article (id, created_by, created_date, created_ip, last_modified_by, last_modified_date, last_modified_ip, version, parent_id, category_id, content, exposed, fixed, fixed_order, thumbnail_id, title, type) VALUES ('8c30330c-7f3e-471d-97f2-8312f68e711c', 'admin', now(), '127.0.0.1', null, null, null, 0, null, '581d25e5-c669-4172-b42d-51831a1f0c4d', '<section class="container-sm my-3"><div style="text-align: center;">대전 포스트잇은<br>매월 마지막 주 토요일에 정기 모임 한 번!<br><br>포스트잇에 자신만의 한 줄 평을 시작으로<br>서로에게 책을 추천하는 시간을 가집니다.<br><br>평소 자유 독서는 아래 링크의 단체채팅방에서<br>이야기 나누며 책 모임을 만들어갑니다.<br><br><br><< 찾아오시는 법 >><br><br>< 모임 단체 채팅방 ><br>* 카톡 오픈채팅에서 ''대전포스트잇'' 검색 *<br>https://open.kakao.com/o/g5set5ng<br><br>< 모임장 연락방법 ><br>* 카카오톡 오픈프로필 ''서담'' 검색 *<br>http://open.kakao.com/me/seodaam<br><br>* Instagram *<br>midnightstory_seodam<br></div></section>', true, true, 4, null, null, 'HTML');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, created_ip, title, content, created_date) VALUES ('26207f35-6247-4507-86d4-39744525b973', 0, true, false, 'HTML', '0236be97-9c8f-4ada-a120-039f540fabee', 'siasiasky1', '127.0.0.1', '아웃오브블루', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/2f10d65c-4496-4aef-b9fd-11bb76ac80f2" data-image-index="1" alt="mosa6P39eE.jpeg" width="257"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/940df1a7-816d-44a7-83c6-807fac5afec8" data-image-index="2" alt="mosaKSjspa.jpeg" width="257"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/c63eb271-4849-493d-8126-9d2289e4cfab" data-image-index="3" alt="mosaB8QVMV.jpeg" width="257"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/f26f7440-2aac-43f5-af82-ea83a33c5043" data-image-index="4" alt="mosaJYC0ok.jpeg" width="257"></div><img src="http://localhost:8080/api/attachments/f189b4bc-6694-4b55-9ae8-7f474b3044f4" data-image-index="0" alt="mosaU9LMUi.jpeg" width="257"></div>서담님의 선물☆<div class="photo_img">따숩♡</div>', '2025-02-23 16:41:22');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, created_ip, title, content, created_date) VALUES ('8b8fb268-9911-4739-9992-8e25b4ce6b4d', 0, true, false, 'HTML', '0236be97-9c8f-4ada-a120-039f540fabee', 'siasiasky1', '127.0.0.1', '푸른 들판을 걷다', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/f0934712-0435-4487-870d-f2e43df3bb3b" data-image-index="0" alt="mosa5F5sx1.jpeg" width="257"></div>클레어키건 작가 신작..<div class="photo_img"><br></div><div class="photo_img">아일랜드설화인듯.. 소설인듯..</div><div class="photo_img"><br></div><div class="photo_img">단편집이라지만 많이 아숩.ㅠ</div><div class="photo_img"><br></div><div class="photo_img">잼잇는 영화&nbsp; 잘보고있는데 갑쟈기 끊나버림.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그래서 그소녀는 어찌됬고</div><div class="photo_img"><br></div><div class="photo_img">그여잔 어디로갓고 남은남잔 어찌된건지. ..</div><div class="photo_img"><br></div><div class="photo_img">중간에 나온 이기적인 남자는 .. 뭔가 벌받앗음 좋겠는데..</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">책을 다 읽엇지만 알수가없음 ㅠ</div><div class="photo_img"><br></div><div class="photo_img"><br></div>', '2025-02-21 19:38:33');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, created_ip, title, content, created_date) VALUES ('e679e7a6-4136-422f-b383-140aef876ef1', 0, true, false, 'HTML', '0236be97-9c8f-4ada-a120-039f540fabee', 'siasiasky1', '127.0.0.1', '나는 나로 살기로했다', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/f14365c5-3e7b-4a9a-b7c8-db41455e50b3" data-image-index="1" alt="mosa7NZI5m.jpeg" width="257"></div>머리로 알고는있지만 하지못하는&nbsp;<div class="photo_img">맘먹기!!!</div><div class="photo_img">긍정긍정!!!<div class="photo_img"><img src="http://localhost:8080/api/attachments/fa94bdd7-c446-437e-aa42-ea68e1061562" data-image-index="0" alt="mosag3NQI3.jpeg" width="257"></div><br><div class="photo_img">올해는 좀더 강한 정신력!!</div></div>', '2025-02-06 19:49:10');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, created_ip, title, content, created_date) VALUES ('4ffed97f-65b6-4443-a961-2c4efe6142bc', 0, true, false, 'HTML', '0236be97-9c8f-4ada-a120-039f540fabee', 'siasiasky1', '127.0.0.1', '맡겨진소녀', '클레어키건&nbsp; 책은...<div class="photo_img">잔잔한 영화한편을 보는느낌..</div><div class="photo_img">늘..끝에 질문하날 던져주는느낌이다..<div class="photo_img"><img src="http://localhost:8080/api/attachments/e5c9ac8b-0238-414d-bd3b-063e8a0de53e" data-image-index="0" alt="mosalDnkpS.jpeg" width="257"></div></div>', '2025-01-25 20:54:24');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, created_ip, title, content, created_date) VALUES ('2f997132-c771-4edc-b1bb-c0277aa1d1f4', 0, true, false, 'HTML', '0236be97-9c8f-4ada-a120-039f540fabee', 'siasiasky1', '127.0.0.1', '미로속아이', '오랜만에 나온 기욤뮈소 신간!!<div class="photo_img">벌써 20주년이라늬 ~ ~</div><div class="photo_img"><br></div><div class="photo_img">설렘과함께 시작..</div><div class="photo_img"><br></div><div class="photo_img">시작과동시에 벌어진 살인사건을 둘러싼 등장인물들과</div><div class="photo_img">그들의서사가 하나하나 흥미진진 하다가</div><div class="photo_img">막판에 반전에서..</div><div class="photo_img">개인적으론 쪼콤 허무..</div><div class="photo_img">와..&nbsp; 이렇게 끝낸다고?...</div><div class="photo_img">혼잣말좀 했습니다...</div><div class="photo_img">기욤뮈소의 책을 보던분들이라면 좀 뻔햇달까</div><div class="photo_img">허무햇을수도..</div><div class="photo_img">그게 아닌분들에겐 식스센스급 반전과</div><div class="photo_img">재미가 있을수도 있을듯 ..<br><div class="photo_img"><img src="http://localhost:8080/api/attachments/987de6b5-7c62-4759-bd8a-5cc4d8fb34ac" data-image-index="0" alt="mosaubPrMd.jpeg" width="257"></div></div>', '2025-01-21 17:39:04');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, created_ip, title, content, created_date) VALUES ('e4720616-775c-4981-8b0d-8805954776c5', 0, true, false, 'HTML', '0236be97-9c8f-4ada-a120-039f540fabee', '4643one', '127.0.0.1', '오렌지와 빵칼 - 청예', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/6e9f1dec-2334-4d9d-a9f1-8123a8e259cb" data-image-index="0" alt="mosaqO9uTY.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">페이지 수가 적은 편이라 하루만에 뚝딱 읽어버린 2025년 첫 도서</div><div class="photo_img"><br></div><div class="photo_img">청예 작가님께는 죄송하지만...</div><div class="photo_img"><br></div><div class="photo_img">내가 느낀 청예 작가님에 대한 소견은...</div><div class="photo_img"><br></div><div class="photo_img">또라이 작가, 철학적인 자기 주관이 뚜렷한 사람.</div><div class="photo_img"><br></div><div class="photo_img">이전에 출간하신 책보다, 앞으로 출간하실 책이 기대됩니다.</div><div class="photo_img"><br></div><div class="photo_img">앞으로 길을 응원하며</div>', '2025-01-02 10:09:30');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('88e0ebdd-f581-4651-8a6c-127c0eab7fc9', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dgh07072', '<확신>', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/dac51136-5826-4440-9667-3d890e91f910" data-image-index="0" alt="mosavaJg92.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">자기확신이 부족한 것 같다는 지인의 이야기를 듣고 찾게 된 책&#x1f4da;</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/4d20a180-aaf9-491f-96ad-568f68d5dd05" data-image-index="1" alt="mosaNdS7uA.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">누가 해준 말을 믿을거냐 생각하니 관계나 직장 문제가 깔끔하게 정리되었다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/94c4e504-7ea1-4657-b01b-0672e650364c" data-image-index="2" alt="mosaVPS0Yu.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">가장 자극이 많이 되었던 구절!!</div><div class="photo_img">항상 심각해지지 말고 가볍고 즐겁게 지내자!!</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/d52a558b-6df8-46f1-8b90-b9e66703b5c0" data-image-index="3" alt="mosaLid4a3.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">자존감이 낮아질 때면 사랑하고 감사하자!</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/8a16cdad-7587-423c-afce-52157f5f30f1" data-image-index="4" alt="mosaku3Ism.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">부자가 되려면 우선 내가 그만한 가치가 있는 사람이라는 것을 깨닫자!!</div><div class="photo_img">타인보다 나를 먼저 사랑하고 인정하고 나의 가치를 인정하자.</div><br>', '2024-12-27 20:05:01');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('ca162e1d-0701-4676-8811-9c66dbc02719', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'siasiasky1', '마지막 마음이 들리는 공중전화', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/c0bb621b-7f09-4580-8161-7a8dbaeff850" data-image-index="0" alt="mosaOqJAAY.jpeg" width="257"></div>살아있음에도 풀어내지못한 관계들이 생각이 났다..<div class="photo_img">죽고나서 알게되는..마음 이라..</div><div class="photo_img">너므 현실적이기도 해서</div><div class="photo_img">생각이 많아지는 책이었다..</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div>', '2024-12-26 20:01:06');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('2f665fce-6825-49be-8722-ea0043a48ea8', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'siasiasky1', '모순..', '양귀자 선생님의 모순..<div class="photo_img"><br></div><div class="photo_img"><br><div class="photo_img"><br></div><div class="photo_img">인생은 진짜 모순 그자체..</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/1fe6608a-e607-4863-868b-b87a1fd2eae1" data-image-index="0" alt="mosal0wnJx.jpeg" width="257"></div><br></div></div>', '2024-12-17 20:53:04');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('568ba79f-a5bc-468c-9ff0-98760b091804', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dbsthd81', '이치조 미사키-이별하는 방법을 가르쳐줘', '이 작가의 기존 작들 최소 세 권은 읽었던 입장에서, 이 작가의 주된 특징이 또 다시 나타날지 아니면 이번에는 드러내지 않을지 생각하면서 읽었다. 이번에도 전작들과 비슷한 방식으로 글을 작성할 것 같다는 생각은 들었지만 또 어떤 점에서 변한 게 있을지 궁금해서 읽었다.<div class="photo_img"><br></div><div class="photo_img">시작은 남들과 잘 어울리지 못하고 따돌림도 당해보았던 남학생의 시각에서 진행되고, 그 남학생 주위에 있는 여학생 두 명에 의해 소설이 진행된다. 단, 이번에는 이전 소설들과 달리 이번에는 사건이 일어나고 있는 시간대를 파악해서 읽어야 한다는 점이 이 작가의 성장한 부분이 아니었나 싶었다.</div><div class="photo_img"><br></div><div class="photo_img">작가의 스타일은 내가 읽었던 세 권의 책과 크게 달라진 것 같진 않지만, 그래도 점점 무언가 설정 장치가 늘어나거나 하는 등 작가의 성장이 보였기 때문에 이 작가의 책을 대부분 읽은 독자로서는 뿌듯한 마음이 들었다.</div><div class="photo_img"><br></div><div class="photo_img">이 작가의 또 다른 작이 있는지 찾다가 알게된 재밌는 점을 하나 있었는데, 별별 정보가 다 오가는 나무위키에 따르면 우리나라에서는 이 작가의 책이 소설로 분류되어 있지만 일본에서는 라이트 문예 쪽으로 분류가 되어 있는 모양이었다. 그렇다는 건 우리나라 번역가가 번역을 잘 했기 때문에 우리나라에서는 소설로 판단하게 되었다는 뜻인건지 아니면 두 나라간 장르 내지 책의 종류를 구분하는 기준이 다른 것인지 궁금해졌다.</div>', '2024-12-12 23:15:55');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('28cf09e0-fb93-4b06-86a0-df5589b38f18', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'nuni8461', '악의 - 히가시노 게이고', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/5663a309-9830-44be-9cf4-f9afb3d6da7a" data-image-index="0" alt="mosaKcLPJu.jpeg" width="257"></div><br><div class="photo_img">어떻게 죽였나보다 왜 죽였나에 주목하는 추리소설</div><div class="photo_img">기승전결,,,,,,전결전결의 느낌</div><div class="photo_img"><br></div><div class="photo_img">이어지는 반전에 참신함보다 피로함이 커질때&nbsp;</div><div class="photo_img">페이지가 끝났고 책을 덮은 후&nbsp;제목의 의미를 다시 되새길때 작가의 의도가 돋보인다</div><div class="photo_img"><br></div>', '2024-12-07 15:07:01');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f23679ac-fe39-4203-aabe-2d7f92467c3d', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '정류장에 두고 온 뉴욕치즈케이크-정덕재', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/67a8c1cc-3c6d-4ae6-abd6-d8aaaac6306d" data-image-index="0" alt="mosa1FKRQy.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">사랑이라는 주제에서 아픔을 걷어내니 시작만 남았다.&nbsp;</div><div class="photo_img"><br></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-12-07 14:40:49');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('5b7d10e0-e2f8-4321-925c-7c02cb2f5d36', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '인간행복-김진향', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/c8a34ee3-d02c-4743-b271-3fbd71b259f4" data-image-index="0" alt="mosaafEcul.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">줄건 주고 최대한 남기겠단 의지를 가진&nbsp;</div><div class="photo_img">작가의 경험에서 비롯된 확신있는 행복철학</div><div class="photo_img"><br></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-12-07 14:39:47');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('536e6431-0ab5-49be-9353-49157282fb2b', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '그 겨울의 일주일', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/fb5bc7fe-c47a-4220-b122-844ec82d44ba" data-image-index="0" alt="mosajXFhci.jpeg" width="257"></div>아일랜드 작가의 원작!&nbsp;</div><div class="photo_img">넷플릭스 10부작 드라마 "그 겨울의 일주일" 이</div><div class="photo_img">나온다면 6화 헨리와 니콜라가 기대된다</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-12-07 14:38:44');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('497f2448-d09f-40d4-8191-f2f9895a5b6a', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '시하와 칸타의 장', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/7cca87ea-1e16-48b2-ad44-b8bc6d7c299a" data-image-index="0" alt="mosa4zUUtW.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">드래곤라자, 폴라리스랩소디, 눈마새 피마새의 이영도.</div><div class="photo_img"><br></div><div class="photo_img">독특한 세계관과 개성 있는 인물들의 유머가 잠 맛깔난다.</div><div class="photo_img"><br></div><div class="photo_img">세계대전 후에 드래곤과 요정, 갓파와 간다르바 같은 환상종들이 나타난 세계라니, 역시 독특하다.</div><div class="photo_img"><br></div><div class="photo_img">웹소설 판타지소설들이 다 비슷비슷한 과자라면,</div><div class="photo_img">이영도의 책은 독특한 맛이 나는 이국적인 디저트다.</div><div class="photo_img"><br></div><br>', '2024-12-07 14:25:15');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('8f0e7ef1-88ef-4efd-bd70-532216e4617d', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '아르슬란전기2', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/19e39e14-ad37-426d-bc62-1c8d9cc8fd05" data-image-index="0" alt="mosa3cNW5Z.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">구매하려고 검색을 해 보았는데 2부는 출판이 안됨.</div><div class="photo_img">1부 판매가 저조하여 그랬단다.</div><div class="photo_img"><br></div><div class="photo_img">아쉽다.</div><div class="photo_img"><br></div><div class="photo_img">끝남이 있는 사랑은 하지 않는 주의라서</div><div class="photo_img">더 읽기를 포기하고 2권으로 만족했다.</div><div class="photo_img"><br></div><div class="photo_img">소설 좋아하시는 분들은 꼭 이 작가의 책인</div><div class="photo_img">&#39;은하영웅전설&#39;을 읽어보시라</div><div class="photo_img"><br></div><br>', '2024-12-07 14:20:32');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('60f92644-e772-40e5-badb-769be6754b30', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dbsthd81', '무라세 다케시-세상의 마지막 기차역', '(지금은 퇴사했지만) 당시 회사에서 1월 초 책 이벤트를 하면서 누군가 나 대신 얻어온 책이었다. 사실 이 책은 작년쯤 유명했다는 건 알고 있었고 나는 좀 유명해진 철이 지난 이후에 읽는 것을 선호했던 터라 설날 쯤에 읽었던 것으로 기억한다.<br><br>네 가지의 챕터를 읽으면서 유령열차에 있던 소녀는 제대로 해결되지 않은 느낌이라 좀 아쉬웠다. 책의 종장쯤에서 짧게 언급하고 지나가서 완전히 그 소녀의 이야기가 풀리지 않은 것은 아니었으나, 신비로운 연출을 하고 싶었기 때문에 이렇게 소녀를 짧게짧게 등장시켰어야 하나 싶었다.<br><br>책 내용은 어쨌든 &#39;사랑&#39;에 대한 이야기를 하고 있었는데 가족 이야기, 연애 이야기로 채웠지만 아이를 먼저 떠나보내게 된 부모의 입장은 여기서 확인할 수가 없어서 아쉬움이 강했었다. 대한민국에서 2021년부터 현재까지 유행하고 있는 스토리라인들과 비슷한 결이 있어서 가족애, 로맨스, 힐링 등을 좋아한다면 가볍게 시간 때우기로 괜찮은 책이었다.', '2024-12-03 14:32:39');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f4586cf8-8e82-43b6-b499-3185691fc750', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dbsthd81', '이꽃님-죽이고 싶은 아이 2', '이 작가는 후속작은 쓰지 않겠다고 다짐했었지만 질문 한 개에 충격을 받아 이 작품을 만들었다고 한다. 등장인물들에 대한 책임을 다하고 있느냐는 질문이었다고 했는데, 솔직한 심정으로는 1에서 마무리 지어도 될 것을 굳이 2까지 내야 하나 싶었다. 옛말에 형 이기는 아우 없다는 말이 괜히 있는 게 아닐텐데 싶어, 반쯤 우려 섞인 마음으로 읽어 내려갔다.<div class="photo_img"><br></div><div class="photo_img">2에서는 사건 이후에, 그리고 1의 결말 이후에 일어난 일들이고 1에 비해서는 심리적인 압박보다 인간 대 인간, 현 사회에 대한 날선 비판 같은 것들이 들어가 있었다. 내용을 자세히 서술하게 되면 1에 대한 스포일러가 되기 때문에 조심스럽게 말하자면 현 시점 사회에서 일어나고 있는 &#39;욕하기 좋은 마녀사냥감&#39;에 대한 내용이 주를 이뤘다. 뭐 하나 제대로 마무리 된 것 같지는 않지만, 그럼에도 어떻게든 나아질 수 있다는 희망을 마지막에 던져주었다.</div>', '2024-12-03 13:30:45');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('baa066f3-7b61-4e4a-8842-c737fab434cb', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dbsthd81', '김지윤-아이들의 화면 속에선 무슨 일이 벌어지고 있는가', '2010년대 스마트폰이 보급되기 전에는 닌텐도 DS가 한창 아이들 사이에서 유행하던 시기가 있었다. 그 때도 많이 들었던 말은 &#39;제발 밥 먹을 땐 화면 보지 말아라.&#39;, &#39;화면 속에 꿀 발라놨냐, 왜 자꾸 화면만 보냐&#39; 등의 잔소리였다. 솔직한 심정으로 그 땐 그게 그렇게 재미있으니 많이 봤다고 생각한다. 그 잔소리는 스마트폰이 보급되면서 스마트폰으로 옮겨갔다. 그렇지만, 단순 재미만으로 내가 닌텐도 DS를, 그리고 지금은 스마트폰을 붙들고 살았던 것은 아닐 것이라는 생각이 든다.<div class="photo_img"><br></div><div class="photo_img">더 생각해보니 스마트폰 압수 등이 그렇게 나는 싫었다. 대체 내 사생활을, 왜 그걸 빼앗아 가는 건지 도무지 알 수 없었다. 당시에는 삼성페이 등의 기능이 없어서 사실 핸드폰이 없어도 연락만 되지 않을 뿐 불편한 건 그렇게 없었음에도 불구하고 정말로 내 생활의 일부를 떼어가는 게 싫었다. 그런데 이런 현상이 지금의 아이들에게는 더 크게 와닿는다고 한다. 나는 내 사생활이 간섭받는 게 싫었다고 느낀 정도지만 저자가 말하기로, 요즘 세대 아이들은 자기 자신을 억압하는 느낌이 더 강하다고 한다. 사생활에서 그치는 문제가 아니라고 한다.&nbsp;이렇게 된 것에는 화면 의존성도 있겠지만, 많은 인간관계들이 화면 속에서 이뤄지기도 하기 때문이라고 설명했다.</div><div class="photo_img"><br></div><div class="photo_img">이 책은 누군가가 내 심정을 분석해서 글을 전문적으로 써주길 바랐던 시절이 생각이 나서 중간중간 웃으면서 보긴 했으나, 그럼에도 불구하고 책장이 잘 넘어가지는 않아서 상당히 오랜 시간 동안 읽었었다.&nbsp; 아이들을 키우는 사람들 또는 아이들을 전문적으로 다루는 사람들은 한 번쯤 읽어볼만 하다고 생각했다.</div>', '2024-12-01 15:38:42');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('d94c07b6-a5b7-460c-b751-2da02cab6564', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'siasiasky1', '클레어키건_이처럼 사소한 것들', '그닥 두껍지않아서<div class="photo_img">..무엇이 사소한것일까 ..가볍게 읽기 시작햇는데</div><div class="photo_img"><br></div><div class="photo_img">아즈 예전에 들었던 막달레나세탁소얘기가 겹쳐서..</div><div class="photo_img"><br></div><div class="photo_img">.. 중간중간 목이메였다..</div><div class="photo_img"><br></div><div class="photo_img">. .주인공의 아내가 그랫다..</div><div class="photo_img"><br></div><div class="photo_img">사람이 살아가려면 모른척해야하는일도 있는거라고</div><div class="photo_img">그래야 계속 살수있다고..</div><div class="photo_img"><br></div><div class="photo_img">내가 주인공이었다면..</div><div class="photo_img">모른척했을까</div><div class="photo_img">아님..</div><div class="photo_img">무얼할수있었을까..</div><div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/a9fe465c-ad4b-446e-a942-1db66bc9c64d" data-image-index="0" alt="mosaxhYPK1.jpeg" width="257"></div><br></div><div class="photo_img"><br></div>', '2024-12-01 09:57:11');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('a3d209b3-c8a6-4e81-b028-5122ec966de8', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dbsthd81', '다자이 오사무-인간실격', '포스트잇 독서모임에 들어와서 제일 처음에 읽었던 책이다.<div class="photo_img">사실 이 책을 선정하게 된 계기는 현재 살고 있는 집에 있는 종이책이라고는 이거랑 이미 읽어버린 책들밖에 없었기 때문이었는데, 그것 말고도 연초 회사에서 북데이 이벤트에서 획득한 책이었기 때문에 완독을 하고 싶었기 때문이었다.</div><div class="photo_img">그리고 더 솔직한 이야기를 하자면, 문장 하나하나가 잘 쓰인 문장이라고 친구가 평했기 때문도 있었다. 솔직히 &#39;부끄럼 많은 생애를 보냈습니다.&#39; 라는 이 문장을 듣고 잘 썼다고 생각하지 않을 사람이 어디 있겠나 싶었다.</div><div class="photo_img"><br></div><div class="photo_img">그런데,&nbsp; 문장은 굉장히 잘 썼지만, 내용은 지독하였다. 지금 세대를 살아오는 사람의 입장에서 이 인간실격을 읽는다면 뭐 저런 사람이 다 있는가, 이렇게 살았기 때문에 부끄럼 많은 생애를 살아왔다고 스스로를 반성 또는 변명하고 있는 것인가 하는 생각마저 들게 된다. 그러면서도 화자를 당시 시대를 살아가는 사람들 중 한 명으로 본다고 하면 그냥 무기력하고 우울한 사람을 보여주는 장치로서 사용한 것이 아닌가 하는 생각마저 들었다.</div><div class="photo_img"><br></div><div class="photo_img">보면 볼수록 독자가 불쾌해지는 기분이고 암울해지는 느낌을 받아서, 만일 감정 동화를 잘 느끼는 사람이라면 이 책은 추천하지 않고 싶다. 그러나, 문장 하나하나를 곱씹어서 보고 싶은 사람들이라면 잘 쓴 문장들도 많기 때문에 그 점에 있어서는 읽어봤으면 하는 생각이 들었다.</div>', '2024-11-30 17:15:57');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('df56b762-2f31-405c-bbba-4ea3159ff3c9', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dbsthd81', '이꽃님-당연하게도 나는 너를', '포스트잇에 들어오기 전, 혼자 밀리의 서재로 이 작가의 &#39;죽이고 싶은 아이&#39;라는 책을 읽은 적이 있었다. 마지막에 반전을 보여주고, 주인공과 수사를 하려는 쪽의 심리전을 보여주는 책이었던 걸로 기억한다. 당시 소설의 작성 방식이 마음에 들어서 이 작가의 책은 다시 한 번 읽어보고 싶다는 생각을 했었다.<div class="photo_img">그러던 중, 죽이고 싶은 아이 2가 나왔다는 소식을 들었고, 이 작가의 다른 책도 있다는 이야기를 들어서 번개모임 때 읽게 되었는데 쉬지 않고 읽었던 것 같다.</div><div class="photo_img"><br></div><div class="photo_img">책의 내용은 남학생 하나가 실종된 것으로 시작된다. 남학생의 여자친구인 학생을 찾아온 경찰은 여학생에게 진술을 요구하는데 여학생은 진술 대신 그 동안 남자친구와 있던 이야기들을 토로하기 시작했다. 여학생의 진술로만 보면, 여학생이 심한 가스라이팅 피해자로 보일 수밖에 없었는데 여학생의 시각에서 문제를 살펴보면 어딘가 맞지 않는 진술들이 생기는 느낌이 든다. 그리고 그 느낌은 결말에서 다시 드러나게 된다.</div><div class="photo_img"><br></div><div class="photo_img">경찰과 여학생의 심리전, 그리고 미묘하게 어긋나는 진술을 파헤치는 것을 좋아하는 독자라면 좋아할 것이라 생각하는 구조로 되어 있었다.</div>', '2024-11-30 16:57:51');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('1935b064-d27c-451e-9620-2d6c30c8ebc7', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', '4643one', '세컨드브레인 - 티아고포르테', '<div class="photo_img">◆ 우선 이 책은 어떤 책인가?</div><div class="photo_img">&nbsp;세컨드 브레인, 삶의 질을 높이는 방법을 제시하는 책. 각종 지식과 정보에 치이지 않고 잘 수집, 정리하여 추출, 표현을 통해 새로움을 창조할 수 있도록 도와주는 책.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"> ◆&nbsp; 깨달음</div><div class="photo_img">&nbsp;이미 일상 속에 어렴풋이 대입하던 것들도 있으나, 이 책을 통해 그동안 무자비하게 해오던 수집들(북마크, 책갈피, 스크린샷, 링크 공유 등…)을 어떻게 잘 정리해야 하는지, 그리고 이 정리된 정보들을 어떻게 추출하고 표현해나가야 하는지 길잡이가 되어준 책이다.</div><div class="photo_img">&nbsp;처음부터 욕심부리지 않고 과다한 정보가 아닌 내가 관심 있어하는 정보 1, 2가지 주제를 시작으로 점차 확장시켜 나가야겠다는 목표가 생겼다. 일상에도, 업무에도 잘 녹여낸다면 앞으로 더 밀도있는 삶을 살 수 있겠다 싶다.(내가 추구하는 삶이므로, 오늘보다 더 나은 내일이 벌써 기대가 된다&#x1f33c;)</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"> ◆&nbsp; 요약</div><div class="photo_img">1.&nbsp; CODE=발산(수집&gt;정리)&gt;융합(추출&gt;표현)</div><div class="photo_img"><br></div><div class="photo_img">2. 발산과 융합은 직선으로 뻗어나가지 않고 순환한다.</div><div class="photo_img"><br></div><div class="photo_img">3. PARA 기법 : 발산 중 정리를 위한!<br></div><div class="photo_img">수집은 흥미로운 지식들을 모으면 되는 것이니까 쉬운편일 수 있으나&nbsp; 마음을 울리는 공명하는 지식들 만을 모으도록 주의토록 한다. 그리고 수집된 이 정보들을 보관할 때&nbsp; "PARA" 기법을 활용하여 보관하면 수월하다.</div><div class="photo_img">&nbsp;1) Projects(프로젝트) : 일상 생활에서 현재 진행 중이며, 단기간 노력이 필요한 일</div><div class="photo_img">&nbsp;2) Areas(영역) : 오랫동안 관리하고 싶고 장기적으로 책임지는 일</div><div class="photo_img">&nbsp;3) Resources(자원) : 향후 도움이 될 수 있는 주제 혹은 고나심사</div><div class="photo_img">&nbsp;4) Archives(보관소) : 전에는 위의 세가지 유형에 속했지만, 지금은 비활성화된 항목</div><div class="photo_img"><br></div><div class="photo_img">4. 융합을 위한 기법들<br></div><div class="photo_img">&nbsp;1) 아이디어 군도 - 징검돌을 이어주어 군도를 이루게 만드는 : 디지털 활용하여 메모해둔 흥미로운 지식들을 활용하여 군도를 만들라(메모에 하이라이트, 볼드와 같은 기능을 통해 나의 흥미도를 표현해라) / 각 표시에 출처든 링크든 메모든 최대한 마인드맵과 같이 융합하라</div><div class="photo_img">&nbsp;2) 헤밍웨이 다리 : 일할때도 마찬가지. 끝을 염두해두고 시작하라. 오늘 그만 멈추고 오늘의 남은 에너지와 추진력을 내일의 활동에 매진할 연료로 쓰는 것. - 이때 그만 멈춘다는 의미는 간단한 디지털 메모로 남기는 것.(다음상황해야할것, 현재상황기록, 금방잊어버리기 쉬운 세부사항 기록, 다음작업시간목표기록)</div><div class="photo_img">&nbsp;3) 범위(scope) 축소 : 융합과정에 추천하는 기법 중 하나</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img">◆&nbsp;&nbsp;마지막으로</div><div class="photo_img">351 page에 달하는 이 책의 알짜를 추출하여 공유하고 싶었으나, 요약의 힘이 부족하여 자세한 내용이 궁금하시다면 이 책을 권해드립니다.</div><div class="photo_img">그리고, 이 책을 추천해주신 “서담”선생님께 감사를 표합니다.</div><div class="photo_img"><br> </div><br></div><div class="photo_img"><br></div>', '2024-11-27 15:37:59');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('eaad2a4e-cc6e-4a94-adc4-80c84a849959', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'siasiasky1', '몬스터', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/abf76693-32db-4bae-ae40-fe22b8bc9e41" data-image-index="0" alt="mosaONOfkT.jpeg" width="257"></div><br></div><div class="photo_img"><br></div>너무나 좋아하는 작가인<div class="photo_img">넬레노이하우스의&nbsp;</div><div class="photo_img">타우누스시리즈&nbsp;</div><div class="photo_img">11번째 작품!!</div><div class="photo_img">너무나 방가운 강력11반 형사들</div><div class="photo_img">피아 와 보덴슈타인 ..을 시작으로</div><div class="photo_img">바로 시작된 실종과 살인사건..</div><div class="photo_img">그러다 급 등장한 판사와</div><div class="photo_img">&nbsp;쌩뚱?맞은 사적제재..</div><div class="photo_img"><br></div><div class="photo_img">너무많은 등장인물</div><div class="photo_img">어찌 흘러가는거지..</div><div class="photo_img">무슨일이벌어진거지</div><div class="photo_img">조금은 산만하던 ..</div><div class="photo_img"><br></div><div class="photo_img">하지만</div><div class="photo_img">역시나 넬레작가님 특유의 몰입감과&nbsp;</div><div class="photo_img">반전이 기가막히면서... 허무하기도..</div><div class="photo_img"><br></div><div class="photo_img">제목이 왜 몬스터지?</div><div class="photo_img">누가 몬스터지 ?</div><div class="photo_img">호기롭게 시작햇던 책이지만</div><div class="photo_img"><br></div><div class="photo_img">너므</div><div class="photo_img">현실적인 사건들..이었기에..&nbsp;</div><div class="photo_img">씁쓸하기도 했어요</div><div class="photo_img"><br></div><div class="photo_img">무고한 난민..</div><div class="photo_img">피해자..</div><div class="photo_img">진짜범죄자..</div><div class="photo_img"><br></div><div class="photo_img">법체계 안 에서 얍삽하게&nbsp; 벗어나는사람들..</div><div class="photo_img"><br></div><div class="photo_img">그들을&nbsp; 직접 처리하겟다며 살인도 서슴지않던&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그들..</div><div class="photo_img"><br></div><div class="photo_img">.. ..</div><div class="photo_img"><br></div><div class="photo_img">무고햇던 누군가를..</div><div class="photo_img"><br></div><div class="photo_img">미디어와 매스컴의 자극적인 기사에..</div><div class="photo_img">&nbsp;범죄자프레임을 씌어놓고</div><div class="photo_img">그냥 비난하고 매도해버리는&nbsp;&nbsp;</div><div class="photo_img">우리..</div><div class="photo_img"><br></div><div class="photo_img">누가</div><div class="photo_img">몬스터 일까..?</div><div class="photo_img"><br></div>', '2024-11-24 07:19:08');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('65afe899-a08b-43e8-ba60-4efc47b4f3b3', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '아르슬란 전기', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/08c88eed-36a5-47b2-99fd-0a8468c64786" data-image-index="0" alt="mosaK9ggbq.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">&#39;은하영웅전설&#39;을 쓴 다나카 요시키의 책이다.</div><div class="photo_img">예전부터 읽어봐야지 하고 생각만 하고는 이래저래 기회가 없던 책인데, 마침 알라딘에 있어서 사게 되었다.</div><div class="photo_img"><br></div><div class="photo_img">역시나 기대만큼 재미있었다.</div><div class="photo_img">다양한 인물들이 등장하고 정치와 종교, 전쟁 등 국가간의 갈등을 크게 크게 그려내는 작가의 글솜씨에,</div><div class="photo_img">금방 읽고 다음 권을 기다리게 만드는 책이었다.</div><div class="photo_img"><br></div><div class="photo_img">망국의 왕자가 동료들을 모아 나라를 재탈환한다는 흔한 스토리지만, 그 안에 인물들의 개성과 특색이 잘 어우러지고</div><div class="photo_img">선악의 구별 없이 각자의 믿음과 가치를 가지고 맞부딪히는 구도가 흥미진진했다.</div><div class="photo_img"><br></div><div class="photo_img">내가 같은 책을 5번 넘게&nbsp; 반복해서 읽은 작가들로는</div><div class="photo_img">이우혁(퇴마록), 이영도(드래곤 라자), 윤현승(하얀 늑대들), 이상균(하얀 로냐프 강),</div><div class="photo_img">그리고 다나카 요시키의 은하영웅전설이 있다.</div><div class="photo_img"><br></div><div class="photo_img">이름이 유치한 감이 있지만 내용은 유치하지 않다.</div><div class="photo_img">장편소설 좋아하시는 분은 꼭 한번 읽어보시기를 추천한다.</div>', '2024-11-20 11:14:01');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('842b0e51-26c7-4289-bb77-815375ea3595', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'hwanggiumin', '왜 일하는가', '일본에 굉장히 열악한 환경에서 연구를 하는 연구자가 자신에 처지에 괴로워 하고 다른 사람들이 자신이 하는일을 그저 보여주기용 이라고 말하고 자신도 정말 그럴지도 모른다고 생각하며<div class="photo_img"><br></div><div class="photo_img">연구실에서 눈물을 흘리면서도 자신에 일을 진심으로 사랑하고 좋아해보자는 생각을 하면서 불가능해 보이던 원자재(세라믹)를 만들어 내면서 이야기가 시작된다.</div><div class="photo_img"><br></div><div class="photo_img">이 이후에 점차 직급이 올라가면서 대기업에 원자재를 납품 하면서 일어나는 문제들을 하나씩 해결 해 나가기 시작하는데 품질을 더올리는 과정</div><div class="photo_img"><br></div><div class="photo_img">대기업에 원자재를 납품 하면서 불량률을 낮추는 과정 납기일을 당기며 납품양을 늘리라는 횡포에 가까운 요구에 굴하지 않고 다른 경쟁자들은 다 나가 떨어지는데</div><div class="photo_img"><br></div><div class="photo_img">버텨내어 거의 단독 납품업체가 되어 회사를 일으키는 과정을 꽤 디테일 하게 이야기 해준다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그래도 책에서 이야기 하고자 하는건 변하지 않는다. 일을 하면서 항상 완벽하게 하려고 하고 그 어떤것 과도 타협하지 않는다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">이렇게 일에 몰입 하다보면 여러가지 일하면서 생길수 있는 자잘한 문제들은 자연히 사라질 것이라고 한다.</div><div class="photo_img"><br></div><div class="photo_img">(뭐 몰입해서 열심히 일하다보면 일을 하면서 스트레스를 덜 받을것이고 부당한 상황도 그냥 받아들이고 넘길가능성이 높기 때문에 이런 과정을 격다보면 회사는 이런 인재를&nbsp;</div><div class="photo_img">&nbsp;승진 시킬 가능성이 높긴 하다. 하지만 그것도 경영진에게 어필 될수 있을만한 일을 하는 사람들에 한해서 일것 같다.)</div><div class="photo_img"><br></div><div class="photo_img">일을 하는 마인들 외에도 자신이 상급자일때 밑에 직원에게 일을 맡기는 법도 알려주는데 낙관론자와 비관론자에 콜라보레이션을 굉장히 높게 치는것 같다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">자신은 낙관론자여서 무언가 일이 있다면 일단 해보자 하다가 잘못되면 그때 문제 해결법을 또 찾아보자고 하는 타입 이지만 비관론자들은 시작도 전에 어떠한 문제가 있을것 같다고&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">하면서 자신이 하는 일에 훼방을 놓는다고 표현한다. 그래서 일을 맡길때는 낙관론자를 불러서 한번 해보겠습니다! 하는 말을 듣고 비관론자를 그에 조수로 붙여&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">실질적으로 실행 가능한 계획을&nbsp;세우는데 도움을 주라고 지시 한다고 한다. 그럼 낙관론자는 그 비관론자에 계획을 실행 시키기 위해 추진력을 제공 하고&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">낙관론자가 일을 진행하다가 놓치는 부분이 있을때 비관론자가 옆에서 서포트를 하며 결국 일이 바르게 진행 될수 있다고 하면서 말이다.</div><div class="photo_img"><br></div><div class="photo_img">마지막으로 인생 공식 같은것도 알려 줬는데 적어 두고 가겠다.</div><div class="photo_img"><br></div><div class="photo_img">인생 = 능력(재능) x 열의(성의.정성) x 사고방식(+ 긍정적 - 부정적)</div><div class="photo_img">&nbsp;&nbsp;</div><div class="photo_img">10(능력) x 10(열의)x10(긍정적 사고) = 100점&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">이런식으로 플러스 인생을 사는 인간이 되라고 말하고 부정적인 사고를 하면 마이너스형 인간이라고 불렀다.</div><div class="photo_img"><br></div><div class="photo_img">인생을 살면서 재능이나 능력이 참 중요하지만 그게 전부가 아니라고 말한다.&nbsp; 능력이 없더라도&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">10x70x10 =7000점</div><div class="photo_img"><br></div><div class="photo_img">70 x5x(-10)=- (-3500점)</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;이런 식에 결과도 충분히 나올수 있으니 능력을 대신할 것들을 찾으면 충분히 자신에 부족한 부분을 채우라고 했다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">눙력이 있는 사람이 부정적인 사고를 가지면 말그대로 범죄를 일으켜도 크게 일으킬수 있는 가능성이 있다는 생각이 들었는데&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그렇게 생각하니까 (-3500점)이 굉장히 공감이 되는 수치 였다 (국회의원의 비리.기업가의 탈세 및 불공정 거래 등등)&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">결론: 이런 직원을 한명만 있어도 사장님이 참 흐뭇할거 같다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;&nbsp;</div>', '2024-11-20 10:47:43');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f00d497f-feec-49a6-b0f0-95863e9e97c8', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'hwanggiumin', '자본주의', 'EBS에서 다큐를 먼저 만들었는데, 수상 이력도 어마어마하고 참여하신 교수진도 외국과 국내를 가릴 것 없이 상당하다.<div class="photo_img"><br></div><div class="photo_img">전체적인 이야기는 경제라는 것이 어떻게 만들어져 왔으며 사람들이 서로 자원을 교환하는 과정에서 일어날 수 있는 대표적인 상황들에 대한 설명을 먼저 시작한다.</div><div class="photo_img"><br></div><div class="photo_img">경제에서 가장 기본적으로 가르쳐 주는 내용인 은행에서 이루어지는 돈의 복사(은행은 누군가 천만원을 저금하면 100만원만(출금 대비 금액) 남겨두고 다른 곳에 돈을 대출해 줄 수 있다)에&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">대한 내용을 길게 이야기해준다.</div><div class="photo_img"><br></div><div class="photo_img">적금, 펀드, 보험 등 은행에서 우리에게 추천하는 모든 것들은 이 제품이 진짜 좋아서가 아니라 이 제품이 은행에 마진이 많이 남는 상품이기 때문에 추천한다는 사실을 말해준다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">사실 나한테 이득이 적은데 양심적으로 고객한테 좋은 상품을 권하는 직원은 본인의 신념이 개입되지 않는 이상 힘들 것으로 보여 공감한다.</div><div class="photo_img"><br></div><div class="photo_img">책을 읽다 보니까 나에게 한 달에 얼마씩 받으면서 아주 양심적으로 내가 가진 돈을 안전하게 좋은 곳에 투자하고 운영할 수 있게 도와주는 재무설계사가 있었으면 좋겠다고 생각했다.</div><div class="photo_img"><br></div><div class="photo_img">이 뒤에는 자본주의의 장점과 단점에 대한 이야기와 단점을 상쇄하기 위해 나온 사회주의 같은 경제 체제들에 대한 이야기와 이것을 만든 사람들에 대한 이야기가 자세히 나와 있다.</div><div class="photo_img"><br></div><div class="photo_img">가장 생각이 많았던 부분은 자본주의의 단점에 대한 것이었다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">열심히 노력하는 자가 모든 것을 가져가는 승자 독식 시스템으로 인해 수많은 성공한 사업가들이 나오고 스타가 배출되었지만, 100명이 사는 곳에&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">1명이 엄청난 자원을 끌어 앉고 결국 사람은 하루에 3끼만 먹으면 (자원의 순환 문제를 비유했다.)충분하기 때문에 가지고 있는 자원이 나머지 99명에게&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">도움이 되게 쓰일 기대를 할 수 없다는&nbsp;것이 가장 큰 단점이다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">여기서 정부는 부자들에게 상당한 세금을 납부시켜 부의 재분배를 일으키고, 거기서 나오는 자원으로 세상에 안전벨트(기초생활수급 이나 각종 개인파산 시스템 등등)를 만들었다.</div><div class="photo_img"><br></div><div class="photo_img">최대한 많은 사람들이 재기 불능이 될 만한 일에도 다시 살아갈 수 있도록 보험을 만들어 주는 것이다.(뭐 그것도 적당히라는 게 있겠지만)</div><div class="photo_img"><br></div><div class="photo_img">이 결과 더 많은 사람들이 이 보험을 믿고 더욱 창의적으로 과감한 일들에 도전하고, 거기서 실패자와 성공자가 또 나오면서 이 세상에 있는 대기업들이 탄생하게 되는 계기가 되는 것이다.</div><div class="photo_img"><br></div><div class="photo_img">역시나 여기서도 전제는 모든 사람들이 이 보험을 믿고 열심히 일을 한다는 전제하에 아름답게 굴러가는 것이지만</div><div class="photo_img"><br></div><div class="photo_img">세상은 그렇지 않고 아무것도 하지 않고 복지만 챙기며 살아가는 자들도 있기&nbsp;때문에 또 다시 문제가 된다.</div><div class="photo_img"><br></div><div class="photo_img">선진국들은 직업 교육을 진행하고 일자리도 제시했는데, 거부하면 하던 지원에 90%를 중지하고 그다음에도 거부하면 지원이 중단된다고 한다. 아주 좋아 보인다.</div><div class="photo_img"><br></div>세상을 살아갈 의지가 없는 자들에게 계속 세금이 들어가는 것이 잘못된 일이라는 걸 설명까지 해야 하는 상황에 있다는 게 답답할 뿐이다.<div class="photo_img"><br></div><div class="photo_img">(생각 해보니 제시한 일자리에 들어가서 잠깐 일하는척 깽판 치다가 짤리고 다시 복지를 받으며 살아가는 사람들이 있을거 같아서 짜증이 난다.</div><div class="photo_img">&nbsp; &nbsp;쓰리 아웃 제도 같은것이 있어야 할거 같다. 언제까지 복지가 나올거라고 생각 하지 못하게)</div>', '2024-11-19 14:37:51');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('c080cdd1-4cd0-4fcc-85d9-57bd99f219b3', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'hwanggiumin', '소년이 온다', '<div class="photo_img">5.18 민주항쟁 당시 전두환 군사정권에&nbsp; 대항하던 시민들에 이야기다.</div><div class="photo_img"><br></div><div class="photo_img">묘사가 굉장히 잔인하고&nbsp; 정부와 시위대에 서로의 입장 차이나 왜 시위를 하고 이런 내용이 자세하게 나와 있지는 않다. (직접적으로 언급 되는건 전두환 살인 정권 물러나라! 정도다)</div><div class="photo_img"><br></div><div class="photo_img">한번 쭉 읽어본 결과&nbsp; 민주 항쟁 당시에&nbsp; 자신에 친구를 잃은 사람에 마음과 당시 사람들이 데모를 바라보는 시선 같은 것들이 자세히 묘사되어 있다.</div><div class="photo_img"><br></div><div class="photo_img">필터가 없다는 표현이 적당하다 싶을 정도로 어린남자아이.평범한 여자 회사원 등등 등장인물들이 어떤 피해를 입고 어떤 감정 상태를 가지고 시간이 흐르는지 설명하고</div><div class="photo_img"><br></div><div class="photo_img">심지어 군인에게 죽은 아이가 시체가 되어 공터로 옮겨져 소각 되는 과정을 표현 하는 부분도 있는데 아직 시체에 어린아이에 영혼이 떠나지 않은 상태인 것으로 묘사하여</div><div class="photo_img"><br></div><div class="photo_img">읽고 있는데 좀 서늘한 느낌이 들 정도였다.</div><div class="photo_img"><br></div><div class="photo_img">느낀점을 정리하자면 전두환정권에 대항하던 시민들이 정부 경찰이나 군인들에게 잡혀가거나 피해를 받고 그 이후로도 그 충격에서 벗어나려고 노력하거나 그러지 못하고</div><div class="photo_img">무너지는 사람들에 이야기를 적나라하게 소설에 형태로 보여준거 같다. 내용은 딱히 특별할게 없지만 (지극히 개인적인 견해다) 자신이 받은 피해나 상황을 등장인물이 본인 스스로 서술하는 부분에서 끝말을 뭐뭐했어 그랬었어&nbsp; 같이 계속 반복하는게 진짜 사람들이 넉두리를 하는거 같아서&nbsp; 표현이 참신한 느낌도 있었고 이제까지 읽어본 소설들이랑 표현 하는 방법도&nbsp;</div><div class="photo_img">많이 달라서 신기하게 읽은 책이였다.&nbsp; &nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div>', '2024-11-17 22:31:31');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('19c03b24-b222-4560-8460-25b909dcfbf2', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', '4643one', '당연하게도 나는 너를 - 이꽃님', '<div class="photo_img"># 책 선택 이유?</div><div class="photo_img"><br></div>1. 이꽃님&nbsp; 작가의 소설 "여름을 한 입 베어 물었더니" 를 재밌게 읽던 기억으로, 이 책을 골랐다.<div class="photo_img"><br></div><div class="photo_img">2. 누군가 읽고 있는 모습을 보고, 앗 나도 읽어볼까?</div><div class="photo_img"><br></div><div class="photo_img">3. 표지가 마음에 들었다.<br><div class="photo_img"><br></div><div class="photo_img">4. 기타 등등</div></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"># 한줄 평</div><div class="photo_img"><br></div><div class="photo_img">조여오는 몰입감과, 알 수 없는 기분 나쁨 = 책에게 가스라이팅 당하는 기분</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"># 느낀 점</div><div class="photo_img"><br></div><div class="photo_img">나는 책을 고를 때, 어떤 주제의 책일까 먼저 상상하고 읽기보다는 그냥 꽂히면 읽는 스타일이다.</div><div class="photo_img"><br></div><div class="photo_img">근데 이 책은 이전에 접했던 작가님의 책이었기에, 약간 편견을 갖고 읽게 된 것 같다.</div><div class="photo_img"><br></div><div class="photo_img">"이전 책(여름을 한 입 베어 물었더니-이꽃님)과 같이 풋풋하고 기분 좋은 그런 소설이려나? "라는 편견.<br><br></div><div class="photo_img">근데 읽으면 읽을 수록 상상했던 내용과 전혀 다른 전개였다.</div><div class="photo_img"><br></div><div class="photo_img">점점 조여오는 몰입감과 이상하고도 기분나쁜 가스라이팅, 아마도 난 주인공 [김해주]한테 가스라이팅을 당했나보다.</div><div class="photo_img"><br></div><div class="photo_img">아마 작가님이 상상하는 독자의 반응이 이런 거러면, 성공하셨다...</div><div class="photo_img"><br></div><div class="photo_img">글이 더 길어졌다간, 스포일러가 될 것 같아 이만 줄인다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/28c2721a-f7b7-4ec4-bc11-10579cdb8152" data-image-index="0" alt="mosa7nodW2.jpeg" width="438"></div><br></div><div class="photo_img"><br></div><div class="photo_img">그래서 다음은 어떤 책을 읽을까?&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">행복한 고민중 :)</div><div class="photo_img"><br></div>', '2024-11-15 15:04:37');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('6fe70b2c-4268-47d3-90f3-e84ab3adeda4', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'hwanggiumin', '데일 카네기 인간관계론', '책을 고른 이유는 베스트셀러도 아닌 스테디 셀러 였기때문이였고 잔뜩 기대하며 읽어 나가기 시작했지만 알수 없는 불쾌감과 그다지 뒷내용이 궁금하지 않은 책이였다.<div class="photo_img"><br></div><div class="photo_img">앞부분을 읽으면서 들었던 생각은 부정적인 감정을 아예 배제한뒤 다른 사람에게 좋은말만 해서 긍정적인 결과를 만들어 내라며&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">유명인의 일화를 가져 오는데 가장 유명한건&nbsp; 링컨에 사례와 각분양에서 성공한 위인들의&nbsp; 사례 였다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">내용을 가져 오자면 링컨이 미국에서 남북전쟁을&nbsp; 진행 할당시 전쟁에 사항을 보고 받으며&nbsp; 드디어 전쟁을 끝낼수도 있는 최고의 기회를&nbsp;</div><div class="photo_img">포착 한다.&nbsp; 링컨은 바로 군대에 장군에게 상대가 불리한 상황을 이용하여 어서 총공격을 진행 하라고 했으나 장군은 이것저것 이유를 대며&nbsp;</div><div class="photo_img">공격을 진행 하지 않았고 결국&nbsp; 아군이 우물쭈물 대는 사이 상대측은 불리한 상황에서 벗어나며 가까웠던 승리는 멀어지게 됐다.</div><div class="photo_img"><br></div><div class="photo_img">링컨은 분노 했고 당장 장군은 앞으로 불러와 다그치고 싶었지만 현장에 있는건 그사람 이고 그사람이 판단이 멀리떨어진곳에 보고를 받는 나보다 정확할것이라고 스스로</div><div class="photo_img">감정을 컨트롤 한다. 그리고 장군에 선택을 비난하는 편지를 작성하여 보내려고도 했지만 그 편지는 발송되지 않은채 링컨 책상 서랍에 보관되어 나중에 발견 되게 된다&nbsp;&nbsp;</div><div class="photo_img">결국 장군을 나무라지 않고 자신에 사람들을 믿고 전쟁을 지속한 링컨은 승리하여 미국에&nbsp; 최고에 대통령중 한사람으로 자리매김 한다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">나는 이사례를 읽고 이런 생각이 들었다. "그럼 뭔짓을 해도 잘했다고 우쭈쭈하면 알아서 잘한다는건가?&nbsp; 인생이 그렇게 쉬운거였나?"</div><div class="photo_img">내 문해력이 잘못된것일수도 있지만 뒤에 곁들여 지는 다른 사례들도 별반 다르지 않았다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">나한테 굉장히 무례하게 대하는 고객 .거래처 .방문판매 까지 상대에 감정을 헤아리고 상대가 누군지 관심을 가져 정보를 얻어 그 정보를 바탕으로 환심을 사고&nbsp;</div><div class="photo_img">절대 상대방에게 부정적인 모습을 일절 보이지 않는다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그나마 괜찮았다고 생각 하는 사례는 호텔에서 공연을 하는 공연단이 있었는데 공연이 유명해지면서 공연객이 늘어나자 공연장 대여료를 늘리는 호텔 사장님에게 공연단장이 말하길</div><div class="photo_img">우리는 상부상조하는관계다. 공연객이 많아 질수록 호텔숙박객도 많아지니 수지타산을 따져서 대여료를 올리지 말아 달라 이런 호텔과 공연장을 가지고 계신 호텔 사장님을 나는&nbsp;</div><div class="photo_img">진심으로 존경한다. 라고 말하니까 대여료를 조금만 올렸다는 것 정도? 이거는 갑을 관계에서 을에 입장인 사람들이 갑에게 무조건 악감정만을 가질때가 많은데 이런식으로 상황을 풀어 갈수도 있겠구나 하는 생각이 들었다.&nbsp; (아쉽게도 이책에서 도움이 될만한 사례는 이게 마지막이였다)</div><div class="photo_img"><br></div><div class="photo_img">가장 치가 떨렸던 부분은&nbsp;&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">고객센터 직원이&nbsp; 블랙켠슈머를 대하면서 너무 힘들었는데 어느날 심경에 변화가 있었서 고객이 하는 이야기를 다 들어주고 이해해 줬더니 그렇게 사납던 고객이 착해졌다는&nbsp;</div><div class="photo_img">내용을 읽고 있는데 진심으로 책 덮을 뻔했다.&nbsp;&nbsp;(국물은 젓가락 먹기가 힘들고&nbsp; 숟가락으로 먹어야한다 라고 써있는 글을 읽는 느낌이였다.)</div><div class="photo_img"><br></div><div class="photo_img">도대체 이책이 왜 일년에 일정량 이상 팔리면 스테디셀러 반열에 올랐는지 전혀 이해할수가 없었다. 잘쳐줘 봐야 국내 베스트셀러 정도랑 비빌거 같다는 생각이 들었다.</div><div class="photo_img"><br></div><div class="photo_img">내가 책을 잘못읽어서 그런것일 가능성이 높다고 생각한다. 꼭 그래야만 한다.&nbsp;&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;</div><div class="photo_img">&nbsp;&nbsp;&nbsp;</div><div class="photo_img">&nbsp;</div><div class="photo_img"><br></div>', '2024-11-14 16:57:56');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('56f36d66-a437-4f1b-97c1-102a178ba033', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'hwanggiumin', '세이노의 가르침', '<div class="photo_img"><br></div><div class="photo_img">모바일 기준 1000쪽짜리 책이라 읽는 데 몇 달이나 걸렸지만, 다 읽고 나니 이것도 다른 책과 다름없는 그냥 책이었습니다.</div><div class="photo_img"><br></div><div class="photo_img">이 책은 부자의 시점에서 세상을 살아가는 이야기를 아주 깊숙이 해주는데서 매력을 느낄 수 있습니다.</div><div class="photo_img"><br></div><div class="photo_img">책 내용 초반부는 일반인이 부자에게 가질 수 있는 편견이나 잘못된 인식을 하나하나 짚으며 부자들을 미워하지 말라는 이야기를 합니다.</div><div class="photo_img"><br></div><div class="photo_img">대표적으로 부자들이 과소비하는 것을 보며 눈살을 찌푸리는 사람들이 많은데, 부자들이 저렇게 돈을 써야 경제가 순환되고 시장에 돈이 돌게 된다는 이야기를 합니다.</div><div class="photo_img"><br></div><div class="photo_img">상속세에 대해서도 이야기를 하는데, 인간의 가장 기초적인 욕구는 사유재산을 가지고 그것으로 자신의 자식들에게까지 물려주는 것입니다. 하지만 우리나라에 상속세는 어느 순간 선을 넘어</div><div class="photo_img"><br></div><div class="photo_img">버렸고, 현재 한국의 재벌들은 한국에 정이 남아 있는 세대가 이를 버티고 있는데, 그 자식들은 애초에 외국과 한국을 넘나들면서 살아 한국에 그렇게까지 정이 없다고 합니다.</div><div class="photo_img"><br></div><div class="photo_img">자식들이 부모의 뒤를 따라 오너가 되면 이제 굳이 부모 세대들처럼 한국에 집착하지 않을 텐데, 이때 상속세 및 세금이 높은 한국을 떠나 외국에 자본을 유치하는 선택을 할 것이라는 것입니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">지금 기업 오너들보다 거부감이 없을 거라는 것이죠. 실제로 싱가포르로 국적을 옮긴 다음 재산을 증여하고 다시 한국에 돌아오는 선택을 하는 재벌가들도 있다고 합니다.</div><div class="photo_img"><br></div><div class="photo_img">이때가 대표적으로 기업에 자본이 해외로 나가는 경우라고 합니다.</div><div class="photo_img"><br></div><div class="photo_img">국내에 굵직한 대기업들이 한국에 있어야 할 이유를 만들어 주는 것이 결국 다 같이 잘 먹고 잘 사는 길이니 기업들을 너무 미워하지 말라는 것입니다.</div><div class="photo_img"><br></div><div class="photo_img">여러 가지 이야기가 있었지만, 신입사원들에게 해주고 싶은 말이라는 부분이 특히 좋았습니다.</div><div class="photo_img"><br></div><div class="photo_img">회사에서 신입으로 일을 하다 보면 "내가 이런 걸 왜 해야 하지?" 하며 중요하지 않은 일을 하고 있다는 것에 불만을 가질 때가 한두 번이 아닙니다.</div><div class="photo_img"><br></div><div class="photo_img">이때 세이노는 커피 심부름을 하더라도, 누구는 이걸 먹고 누구는 저걸 먹는다는 정보를 다 모아서 커피 심부름을 받을 때마다 "이번에도 똑같은 걸로 드시는 걸까요?" 하며 제대로 하는 게 중요</div><div class="photo_img"><br></div><div class="photo_img">하다고 말합니다. 사소한 일조차 똑바로 처리하지 못하는 사람은 큰일이 주어졌을 때 실수 없이 잘할 확률이 거의 희박하다고 이야기합니다.</div><div class="photo_img"><br></div><div class="photo_img">회사 생활이 길어질수록 공감이 가는 말이고, 별거 아닌 일을 대충 하지 않고 체계적으로 시스템화 하면서 완벽하게 처리하는 모습을 내가 봤다고 해도, 그 사람을 끌어다가 다른 일을 시키려는&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">시도를 할 것 같습니다.</div><div class="photo_img"><br></div><div class="photo_img">뒤쪽 이야기에서는 변호사 선임할 때 주의사항, 병원에 가야 할 때 의사들에 대한 디테일한 이야기, 주식, 부동산 등 다양한 이야기가 있습니다. 책 내용 전반적으로 아주 강하게 풍겨 나오는 뉘앙</div><div class="photo_img"><br></div><div class="photo_img">스는 노력하지도 않으면서 불만만 가지고 있는 사람들에 대한 강렬한 비판이었습니다.</div><div class="photo_img"><br></div><div class="photo_img">나도 요즘 그런 생각을 많이 하는 것 같은데, 현재 삶이 불만이고 우울하고 화가 나는 지경입니다. 경우에 따라 유튜브를 보면서 악플 다는 게 전부인 사람들을 종종 보게 됩니다. 어떤 불만이 있</div><div class="photo_img"><br></div><div class="photo_img">고 거기에 대한 해결책을 생각해서 최선을 다해 해보고도 안 된다면, 그때 나오는 불안이나 불만은 들어줄 만한 수준이겠지만, 전자의 경우는 마치 다 큰 어른이 배고프다고 밥 달라고 어린애처</div><div class="photo_img"><br></div><div class="photo_img">럼 진지하게 울고 있는 모습을 보고 있는 것 같습니다. 아닌가? 온갖 무기를 들고 마트로 들어가 다 부수고 음식을 들고 나오는 폭도들이 맞는 걸까요?</div><div class="photo_img"><br></div><div class="photo_img">이 책을 읽으면서 공감이 가는 부분이기도 했고, 나는 사람들이 대안이나 해결책 없이 불만만 가지지 말고 해결하는 방법에 집중하면서 살았으면 좋겠다는 생각을 했습니다.</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;</div>', '2024-11-11 17:46:24');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('7c52bea9-4895-4704-9c19-afb2f491e5ba', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dgh07072', '지적 대화를 위한 넓고 얕은 지식2', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/b6584826-d966-42bc-a2a6-a6bf2b29d84c" data-image-index="0" alt="mosaQtrq4r.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">이번에 읽어본 책은 "지적 대화를 위한 넓고 얕은 지식2" 이다.</div><div class="photo_img">평소 읽고 싶었지만 책장에 꽂아두기만 했던 책을, 독서 모임을 통해 먼지를 털고 꺼내게 되었다.</div><div class="photo_img"><br></div><div class="photo_img">총평 : 철학이라는 주제라 내 기준 심오하고 어려웠지만 진리란 무엇인가에 대해 간략하게 알게 된 책.</div><div class="photo_img"><br></div><div class="photo_img">철학, 진리, 신비, 등에 대해 관심이 있는 사람에게 추천합니다!</div><div class="photo_img">추상적이고 눈에 보이지 않는 무언가를 설명해서 때론 말장난처럼 느낄 때도 있기 때문에, 철학에 대해 관심이 없는 사람은 수면제처럼 느낄겁니다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/67bd433b-d9e3-4751-8d37-91e67488c58b" data-image-index="1" alt="mosapYst2g.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">쉽게 말해, 진리란 절대적이고 보편적이며 불변한 것을 말한다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/32fd637f-d085-45df-a9a6-1fee8033f8da" data-image-index="2" alt="mosa5moUTU.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">인간의 본질은 무엇일까.&nbsp;</div><div class="photo_img">학생, 직장인, 국적, 종교, 등을 다 뗐을 때 "나", "지금", "여기" 만 남게 된다.</div><div class="photo_img">나는 이 부분에서 나는 지금 여기 있기에 현재에 최선을 다해야겠다고 자각하게 되었다.</div>', '2024-11-06 14:00:09');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('c2988291-46ed-4bd7-9943-0a69145daf2f', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '나인-천선란', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/6ca0b7d2-50b3-48e7-ac7c-45a4ba3418a5" data-image-index="0" alt="mosamk11kP.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">"비정상의 정상화"</div><div class="photo_img"><br></div>비정상은 때때로 정상과 줄다리기를 이김으로써</div><div class="photo_img">정상이 되기도 한다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-11-02 18:54:19');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('aae9ac34-3a0a-4ab9-b7aa-8035047a626b', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dgh07072', '오늘부터 성장할 나에게', '<div class="photo_img"></div><div class="photo_img"></div><div class="photo_img"></div><div class="photo_img"></div><div class="photo_img"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/9bd28a49-ba84-4b40-a5b0-a861b0dee35b" data-image-index="0" alt="mosawXcPdn.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">"오늘부터 성장할 나에게" 추천할 사람으로는</div><div class="photo_img">100일 챕터로 나뉘어있는데 긴 글은 읽기 힘든 사람에게 추천합니다.</div><div class="photo_img"><br></div><div class="photo_img">그러나 자칫 진부한 말처럼 느끼는 글도 있었습니다.</div><div class="photo_img"><br></div><div class="photo_img">그래도 전반적으로 위로와 힘이 되는 말이 많아 도움을 많이 받았습니다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/74932886-1f07-4eec-a424-e334d9a61a7a" data-image-index="1" alt="mosaU4m1jr.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">가장 와닿아 친구에게 이야기했던 이야기입니다.</div><div class="photo_img">불안으로 인해 생각이 많아지고 가끔은 현혹되기도 하지만, 결국은 내가 밥을 주는 놈이 이기게 된다는 말에 적잖은 충격과 위로를 받았습니다.<br></div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/b074d092-51f7-4502-adcb-d6e8b3525615" data-image-index="2" alt="mosaAJFY7W.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">가장 큰 위로를 받은 문구입니다.</div><div class="photo_img">그 누구도 당신처럼 당신의 삶을 살 수 없다는 말에 움츠러들었던 자신이 조금은 당당해지는 것을 느꼈습니다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/0e12fe5b-9c94-43cd-9352-9fff77b83838" data-image-index="3" alt="mosamwuFeI.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">남을 위해서가 아닌 나를 위해서 살아갑시다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/f6acc97a-0353-428b-8664-14a5999700d2" data-image-index="4" alt="mosaLBRrSC.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">끊어내고 싶어도 끊어내기 힘든 사람이 있지요?</div><div class="photo_img">전 생각이 많아서 꼬리에 꼬리를 물어 괴롭곤합니다.</div><div class="photo_img">그럴 때 솔루션으로 좋은 방법인 것 같아 공유합니다.</div>', '2024-10-29 16:16:42');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('6f8a6700-675f-4d69-ae5d-eeecb8930c68', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'dkdladpf', '빅터 프랭클 - 죽음의 수용소에서', '유명하고, 베스트셀러이기도 해서 기대를 많이 했던 책이다.<div class="photo_img">그런데 실상 읽어보니, 전쟁중 수용소에 수감되는 상황을 그렇게 잘 묘사하지는 못한 것 같이 느껴졌다.</div><div class="photo_img">이는 책을 읽는 중에 작가에 대해서 실망한 탓도 있다.</div><div class="photo_img">전반부에 수용소에서의 문화와 예술을 말하는 내용이 있었는데,&nbsp;</div><div class="photo_img">한 독일군의 시낭송을 듣고 웃음을 참았다는 장면이었다.</div><div class="photo_img">작가는 예술을 쉽게 생각하는 사람이다.</div><div class="photo_img">자신의 예술만&nbsp; 고귀하고 진정한 예술이라고 생각하는 사람이다.</div><div class="photo_img">어느 누구도 타인의 작품에 대해서 비웃을 수 없다.</div><div class="photo_img">작품에 대해서 좋다, 나쁘다, 잘썼다, 못썼다 논할 수 있어도 비웃을 수는 없다.</div><div class="photo_img">이 장면을 보고서 어떻게 이 책이 베스트셀러가 됐을지 의문이 들었다.</div><div class="photo_img">내가 글을 쓰는 사람이라서 이렇게 과민반응하는 걸 수도 있지만,&nbsp;기분이 너무 나빴다.</div><div class="photo_img">작가가 얼마나 위대하고, 글을 잘 쓰는지는 모르겠지만, 결코 좋은 사람은 아니었을 것 같다.</div><div class="photo_img">올해 읽은 30여권의 책 중 가장 별로인 책이었다.</div>', '2024-10-28 21:38:42');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('c7d1369e-a677-4e7e-bede-0124023660bc', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '결국 해내는 사람들의 원칙', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/c2c718fc-4b39-416f-aec8-779a8e0a1f04" data-image-index="0" alt="mosazeoQvZ.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">자기계발서는 잘 읽지 않지만,</div><div class="photo_img">선물받은 책이라 펴보았다.</div><div class="photo_img"><br></div><div class="photo_img">마인드를 세팅해야 한다는 내용이 중심으로,</div><div class="photo_img">세세한 구체적 방법을 제시한다.</div><div class="photo_img"><br></div><div class="photo_img">글로 써 놔라, 세부계획을 구체적으로,</div><div class="photo_img">여러 목표를 정해놔라, 막히면 돌아가라 등.</div><div class="photo_img"><br></div><div class="photo_img">실천하기는 어려운 것 같다. 말은 쉽지만..</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><br></div><br>', '2024-10-26 11:10:52');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('c6b9eb9c-3738-4dd7-b191-ab02e6302117', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '작은변화에도걱정이많아지는예비엄마들에게', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/2dce385f-d9af-4086-93c5-b576bbb3fb2b" data-image-index="0" alt="mosa7a3flr.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">임신부터 출산까지 생길 수 있는 다양한 질병에 대한</div><div class="photo_img">의학 안내서.</div><div class="photo_img"><br></div><div class="photo_img">아기 하나가 태어나기까지 참 많은 어려움이 있구나,</div><div class="photo_img">내 아이가 아프다면?</div><div class="photo_img"><br></div><div class="photo_img">여러 생각을 하게 만드는 책이다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><br>', '2024-10-26 10:47:22');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('1fc4a89e-e109-40cf-9323-85a701b58a88', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'qoqudwns0302', '[희망의 책 사업]오래된 연장통 - 전중환 (종료)', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/725ecea9-bfcf-472c-a3c0-2babd639fd3e" data-image-index="0" alt="mosayZArmA.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">&nbsp; "사람의 수 만큼 세계가 존재한다"라는 말이 있습니다. 저는 이 말을 들었을때, 사람은 각개 생각이 다르며, 이를 온전히 이해한다는 것은 불가능하다고 느꼈습니다. 하지만 사람이란 끝없이 탐구하고 모르는 것을 알아내고 싶어하듯, 이 불가능함을 가능할 수 있도록 만들어주는 것이 심리학이라 생각합니다. 이런 심리학은 감성적으로 해석하기 마련이지만 이 책은 이를 누구나 이해할 수 있도록 비교적 명료하게 원인과 결과를 나타내고자 했다고 보입니다. 대표적으로 3가지 내용을 적어, 이해를 돕고자 합니다.</div><div class="photo_img"><br></div><div class="photo_img">&nbsp; 1. 사람은 어째서 이타적인 행동을 취할 수 있다고 생각하시나요? 이에 대한 해답을 유전자의 입장에서 해석했습니다. 사람은 생존을 위해 유전자가 조종하고 있다는 얘기도 있듯, 최종적으로 사람이 피해를 입더라도 유전자가 살아남기 위한 행동을 하는 경우가 발생할 수 있다는 것입니다. 지금 당장 손해를 입게 되더라도 포괄적으로 볼 때 이익이 생기거나, 추후 수혜를 입을 수 있는 확률이 비약적으로 증가할 때, 유전자는 자연적으로 이를 선택합니다. 또한 이같은 유전자가 살아남아 이를 도덕이라 부르게 됩니다. 더 나아가 혈연관계에선 그 수혜를 받을 확률이 증가하니, 더욱 끈끈하게 작용할 수 있다고 주장합니다.</div><div class="photo_img">어쩌면 본인 스스로도 이해하지 못하는 이타적 행동들은 우리가 아닌 유전자의 선택일지 모릅니다.</div><div class="photo_img"><br></div><div class="photo_img">&nbsp; 2. 다수의 사람이 모이면 모임이 생기고 자연스레 어느정도폐쇄적인 분위기가 발생합니다. 이 같은 현상을 집단주의라 하는데 이를 질병의 관점에서 해석해보겠습니다. 예부터 인간은 혹독한 환경에서 생존했습니다. 생존 과정에서 힘을 합치기 위해 어쩔 수 없이 집단을 형성하게 되었습니다. 문제는 이미 형성된 집단에 외부인 혹은 타 집단이 만나게 되었을 때 였습니다. 이들은 현재의 집단의 사람이 항체를 가진 병원균이 아니라 다른 병원균을 갖고 들어올 확률이 큽니다. 따라서 그들을 받아들이면 해당 집단이 힘을 잃는 경우가 자주 발생, 경험과 전수에 의하여 배척하게 되었다고 합니다.</div><div class="photo_img"><br></div><div class="photo_img">&nbsp; 3. 사치품은 왜 발생해서 사람을 차별하는 원인이 될까..종종 생각하게됩니다. 이는 수컷 공작의 깃털에 비유할 수 있습니다. 자연 환경에서 이같은 화려함은 사치를 넘어 위험 요소로 작용합니다. 하지만 수컷 공작은 이를 감수하는 방향으로 진화하게 되었는데, 이는 자신이 이같은 위험요소를 갖고도 생존할 수 있는 좋은 유전자를 타고났음을 내세우기 위함입니다. 이와 유사하게, 더 좋고 희소성있는 명품을 보일 수록 자신의 능력을 보일 수 있는 계기가 되므로 이같은 현상이 발생한다고 봅니다.</div><div class="photo_img"><br></div><div class="photo_img">위 세가지 외에도 다양한 예시가 있어 독자가 평소 타인의 이해할 수 없는 행동 및 심리를 이해하는데 도움이 될 것입니다.</div><div class="photo_img"><br></div><div class="photo_img">감사합니다.</div><div class="photo_img">-운동해야하는 라이언-</div><div class="photo_img"><br></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-10-26 00:43:58');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('7cfd953e-27ad-4c40-9a4e-c943bb4451b2', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'lyu328', '밸류에이션을 알면 10배 주식이 보인다', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/0527c612-2966-4943-94f1-47379064c161" data-image-index="0" alt="mosaQWWXC0.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img"><br></div>적정한 기업의 가치와 시장의 평가를 비교하여 부를 이루고만 싶어라', '2024-10-22 20:01:18');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('282c8155-1727-4495-86d6-f61c9d14f57f', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'hwanggiumin', '자기계발서:원씽', '가까운 시일 내&nbsp; 읽었던 책중 가장 도움이 된다고 생각이 들었던 책이라 글을 남깁니다.<div class="photo_img"><br></div><div class="photo_img">책에서 이야기 하는 내용은 제목답게&nbsp; 한문장으로 요약 가능한&nbsp; 수준 이었습니다.&nbsp; &nbsp;</div><div class="photo_img"><br></div><div class="photo_img">제일 중요한 한가지만 해라 단 여러가지 문제가 동시에 해결 될만한 걸로...</div><div class="photo_img"><br></div><div class="photo_img">그리고 나머지 내용은 살면서 일어날수 있는 다양한 문제들을 유명인사들은 제일 중요한 한가지에만 신경써서 어떻게 해결이 됐다 하는 내용 입니다.</div><div class="photo_img"><br></div><div class="photo_img">간단한 예시로 우리 회사에 매출을 올리면서 기업 이미지도 높이는 방법이 있을까? 하는 문제가 발생 했고 임직원 들과 함께 이를 이룰수 있는 100가지에 방법을 찾은뒤 그걸 10개 1개 로 줄여 가면서 마지막으로 남은 방법이 ceo에 자서전을 출간 하는 거였고 책을 내는데에 모든 신경을 집중한 결과 원하는 대로 기업이 성장했다는 이야기 였습니다.</div><div class="photo_img"><br></div><div class="photo_img">저도 살면서 해결해야 하는 문제에 봉착 했을때 막막할때가 많았습니다 당장 뭐부터 해야 할지 이걸 한다고 이문제가 해결 될것인지 확신이 없으니까&nbsp;</div><div class="photo_img">이도저도 안되게 온힘을 쏟지 못하고 눈치만 보는 경우가 많았고 체감 되는 상황이 좋지 않으니까 아무것도 하고 싶지 않아 지더라고요&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그러다가 우연히 운동을 시작했는데 몸무게가 10~20kg 이상 늘고 근육이 몸에 붙으면서 아예 손도 못대던 일들이 자연스럽게 해결이 되는 경우가 있던 적이 있습니다.</div><div class="photo_img">저는 항상 사람들에 눈치를 보고 기분을 살피고&nbsp; 오늘은 저에가 나한테 좀 쌀쌀맞게 구네 오늘은 기분이 좋은가보네 하며 주위 눈치를 진짜 너무 많이 보고&nbsp;</div><div class="photo_img">자존감이 낮고 자신감이 없어 항상 고민이 였는데&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">그것 때문에 에너지가 없는 경우가 허다 했는데 몸이 커지니까 반대에 경우가 되어 주위에 사람들이 제 눈치를 보기 시작하는 겁니다.&nbsp; &nbsp;&nbsp;</div><div class="photo_img">원래 라면&nbsp; 제가 신경을&nbsp; 더써서 처리해야 할일도 알아서 해주느경우도 더러 있고 사람들 사이에서 예전 만큼 에너지를 쓰지 않아도&nbsp;</div><div class="photo_img">인간관계가 제법 잘 유지가 됐습니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">고민을 해결하기 위해 유튜브 따위에서 자기확언.긍정적인말 되뇌이기...등등 이런거를 열심히 했던 때도 있었는데 정말 중요했던거 나지신이 바뀌는 것이였던 거죠&nbsp;</div><div class="photo_img">고민을 해결 하기위해 단하나 내가 해야 했던건 내가 왜 자신감이 없는지를 통찰하고 여러가지 요인들을 묶어서 해결 할수 있는 일을 해야 했던 겁니다</div><div class="photo_img"><br></div><div class="photo_img">그게 운동 이였던 거죠&nbsp; 운동을 하게 되면서 피부도 좋아지고 몸이 커지니까 자신감이 자연히 생기고 남 눈치를 보지 않으니까 나 자신에게 더욱 집중 할수 있고&nbsp;</div><div class="photo_img">남들에게 좋은사람으로 보이고 싶은데 이것도 어느정도 관련이 있고 1석n조에 일이였던 겁니다.</div><div class="photo_img"><br></div><div class="photo_img">운동과 똑같이 책을 읽는것도 여러가지 요인을 싸잡아서 동시에 해결할수 있는 또 하나에 원씽이라고 생각하기때문에 책을 열심히 읽고 뇌에 근육을 붙여야 겠습니다.</div><div class="photo_img">감사합니다.&nbsp; &nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div>', '2024-10-14 12:24:00');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('6336f7f6-a496-4043-895a-ae0b3dd09376', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'jlve', '팩트풀니스', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/7c49a17e-10b0-4402-9c1d-52d29f165f67" data-image-index="0" alt="mosaKu0kJa.jpeg" width="257"></div><div class="photo_img"><br></div>&nbsp;✔️ 서명: 팩트풀니스<div class="photo_img">&nbsp;✔️ 저자: 안나 로슬링 뢴룬드,올라 로슬링,한스 로슬링</div><div class="photo_img">&nbsp;✔️ 번역: 이창신</div><div class="photo_img">&nbsp;✔️ 출판: 김영사<div class="photo_img"><br></div><div class="photo_img">&#x1f4d5; 한줄리뷰<br></div><div class="photo_img">&nbsp;쏟아지는 정보의 바다에서 사실에 근거한 정확한 팩트만을 추려내는 능력을 길러 보다 정확하게 세상을 바라보고 이해하는 습관 들이기!</div></div>', '2024-10-13 21:00:26');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('48f5503f-5960-427c-b461-99feaf11a9a5', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '맹인의 거울 - 정무', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/6afc1eeb-f5bf-488d-8fb6-75eceadd5d23" data-image-index="0" alt="mosaf1L1Sf.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">시각이란 눈이 멀면, 그 외 나머지 감각들이 시각을 보완하기 위해 발달해야 되는데 타자치는 손이 발달한 건에 대하여</div>', '2024-09-25 17:50:46');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('1b41eb6d-dac4-42c2-ad87-7be0807cf495', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '데미안 - 헤르만 헤세', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/2cecd36b-1feb-43cb-921a-90ee74b1c599" data-image-index="0" alt="mosaWkSqz0.jpeg" width="438"><br></div><div class="photo_img"><br></div><div class="photo_img">데미안은 남자인가 여자인가...</div><div class="photo_img">그 이전에 실존은 하는 걸까?</div><div class="photo_img"><br></div><div class="photo_img">데미안이 제 2의 싱클레어라면...?</div><div class="photo_img">이 책은 또 한 번 읽어 볼만 하다.</div>', '2024-09-25 17:47:50');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('6eb9a202-b5f0-440b-8dcf-626daaade5d3', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'wlcogus', '그 겨울의 일주일', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/7e1d112d-9404-411a-afa8-78ef461a12aa" data-image-index="0" alt="mosai7rX6x.jpeg" width="257"></div>메이브 빈치의 몇가지의 단편 소설<div class="photo_img"><br></div><div class="photo_img">첫번째 등장인물 치키</div><div class="photo_img"><br></div><div class="photo_img">외국식 막장드라마를 보는듯하다</div><div class="photo_img"><br></div><div class="photo_img">하지만 한국의 매콤함에는 따라오지 못하는듯..?</div>', '2024-09-22 21:44:14');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('40268112-f399-4077-863f-75388bdd8c68', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '우리의 활보는 사치가 아니야 - 김지우', '<div class="photo_img"><div class="photo_img">대전 시민 같은 책읽기!</div><div class="photo_img">북토크때 받은 책 저도 다 읽었네요 ㅎㅎ</div></div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/9fff6ad2-7ea1-4899-acd3-260e76411906" data-image-index="0" alt="mosamYRdIc.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">- 아직 겪지 않은 자가 이미 겪은 자를 이해한다는 말만큼 오만한 말이 또 없다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">나의 아픔</div><div class="photo_img">너의 아픔</div><div class="photo_img">그들의 아픔</div><div class="photo_img"><br></div><div class="photo_img">이 책 속 인물들은 당신에게 있어 나인가, 너인가 아니면 그들인가</div>', '2024-09-05 20:05:04');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('52fa2507-693e-46ea-8f9f-16070acb923f', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '악의.', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/c08eb9a4-6c92-4eee-bf88-c057d08cbdd2" data-image-index="0" alt="mosaMKWqmL.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">한국적 정서로는 잘 이해되지 않는다.</div><div class="photo_img"><br></div><div class="photo_img">내게 잘해주고 일생의 은인인 친구에 대한,</div><div class="photo_img">비합리적인 악의.</div><div class="photo_img"><br></div><div class="photo_img">내게 잘해줄수록 더 악감정이 쌓이는 뒤틀린 마음이라니?</div><div class="photo_img"><br></div><div class="photo_img">내면의 음습한 마음을 잘 그려낸 책이다. 이해는 안 가도.</div><div class="photo_img"><br></div><br></div>', '2024-09-02 08:58:00');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('e6facdd9-0458-4cd8-84fd-f12ad031cf08', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '우리의 활보는 사치가 아니야', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/b99a734f-9157-42cc-bdd6-4a5837d79001" data-image-index="0" alt="mosaMv6ivI.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">장애인도 사람이다.</div><div class="photo_img">이 말을 머리로는 알아도 진짜로 이해하는 사람은 나 포함 몇이나 될까.</div><div class="photo_img"><br></div><div class="photo_img">저마다의 생각, 욕구, 필요가 있고, 그것이 이상한 것이 아니라는 것이다.</div><div class="photo_img"><br></div><div class="photo_img">이 책은 여러 장애인들의 솔직한 목소리를 담았다.</div><div class="photo_img"><br></div><div class="photo_img">&#39;일상&#39;이 장애인에게는 얼마나 불친절한지,</div><div class="photo_img">사람들의 시선은 어떤지 등.</div><div class="photo_img"><br></div><div class="photo_img">색다른 세상을 본 느낌이었다.</div><div class="photo_img">그게 내가 살고 있는 바로 그 세상인데도.</div>', '2024-09-02 08:54:37');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('da9f9dd8-45af-4b7a-8ecf-9acd959ef6ad', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '게임체인져 기본소득', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/d79897b3-74cd-46a2-a8b8-e39798b9c655" data-image-index="0" alt="mosa00d98l.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">생각보다 어린아이들은 대놓고 말하는 직유보다</div><div class="photo_img">은유를 즐길 줄 안다는 것을 어른들은 모르는 것 같다.&nbsp;</div>', '2024-08-31 12:06:48');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('27d28849-e2b0-4758-991c-c6ab36cbfcd8', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'iamdeuk', '불타는작품', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/5e2fce9e-05fd-41db-965f-99124fd90715" data-image-index="0" alt="mosa7nueBt.jpeg" width="257"></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-08-31 12:06:26');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('e1ff0f85-2476-4861-bab9-78d7f4ab99f6', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'iamdeuk', '환상서점', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/8a2ea31e-8209-4f10-954c-45afa4669f37" data-image-index="0" alt="mosahpEQGb.jpeg" width="257"></div>읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;', '2024-08-31 12:05:54');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('c46179a3-ed28-4118-bcef-18042f1975f1', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '빠져들 수 밖에 없는 캐릭터', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/c01969db-db15-4bef-a464-510ac0fc18cd" data-image-index="0" alt="mosa2WydpR.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">자신감을 잃은 초보 작가에게 희망을 불어 넣어주기 딱 좋은 책</div>', '2024-08-31 12:05:06');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('03fb4656-f2dd-4aef-ad31-4815a81cee73', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '어떻게 살고들 계십니까', '읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;<div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/099ee5d1-7c71-4bc9-8c94-f4548aaef607" data-image-index="0" alt="mosautYUWz.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">한 아이를 키우려면 온 마을이 필요했다.&nbsp;</div><div class="photo_img">이제는 부모가 마을이 되어야 한 아이를 키울 수 있다.&nbsp;</div><br></div>', '2024-08-31 12:04:10');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('07232f83-0cf1-4268-8b03-9c270a85d33a', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'qoqudwns0302', '오래된 연장통 1회차', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/18b25a53-297e-422e-9c96-c55aaa336dfc" data-image-index="0" alt="mosaqYFIyW.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">인간의 행동에 의미 없는 행동은 없다</div>', '2024-08-31 12:02:33');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('22a71e4f-570e-49ac-94e0-8fb9a9d40e1e', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '우린 어쩌다 부부가 됐을까', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/48203835-bb8e-450f-b1f7-a84d5634127a" data-image-index="0" alt="mosaKIpdKQ.png" width="438"></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">제목에 속았다.</div><div class="photo_img"><br></div><div class="photo_img">부부관계에 대한 에세이인줄 알았는데, 처음부터 끝까지 기독교 이야기다.</div><div class="photo_img"><br></div><div class="photo_img">아이가 아파서 기도를 드렸더니 나았다더라.</div><div class="photo_img">부부관계가 나쁘고 서로 이해 못했는데 말씀을 따라 가르침을 어쩌고 하여 좋아졌더라.</div><div class="photo_img"><br></div><div class="photo_img">반쯤 읽고 책을 덮었다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">좋은 말, 건강한 사회를 만들기 위해 서로 돕고 나누는 정신은 좋다.</div><div class="photo_img">그러한 가르침을 말한 성인과 가르침을 따르는 사람들도 바람직하다.</div><div class="photo_img"><br></div><div class="photo_img">그러나 이 책을 읽으면서 보고자 했던 것은 부부 사이 고민과 갈등을 어떻게 헤쳐나갔나 하는 것이지</div><div class="photo_img">그저 기도하면 이루어진다 식의 내용은 아니었다.</div><div class="photo_img"><br></div><div class="photo_img">그래서 책을 덮었고, 다시 펴 보지는 않을 것 같다.</div><div class="photo_img"><br></div>', '2024-08-12 11:12:58');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('b696de6e-6f30-42e0-9bcc-5d5271f05f58', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '감정의 이해 - 엠마 햅번', '읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;<div class="photo_img"><br></div><div class="photo_img">감정은행소속 전문 자산관리사의</div><div class="photo_img">신규고객 유치를 위한 꿀팁 대방출 이벤트<div class="photo_img"><img src="http://localhost:8080/api/attachments/b8b5d208-a0c9-42ad-8296-97d1f66c26d7" data-image-index="0" alt="mosaVQz99y.jpeg" width="257"></div></div>', '2024-07-27 17:01:23');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f45ef801-18e1-41ce-9e31-ec106ac9809c', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '베니스의 상인 - 셰익스피어', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/3a5b3a83-7fb5-4156-9558-80946ca64cde" data-image-index="0" alt="mosarMTAGR.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">샤일록은 천대받는 민족인 유대인 대부업자다.</div><div class="photo_img"><br></div><div class="photo_img">셰익스피어 본인이 살았던 시대를 감안해 보면,</div><div class="photo_img">혐오의 대상을 통쾌하게 격파하는 그런 내용이다.</div><div class="photo_img"><br></div><div class="photo_img">요즘은 혐오의 시대다.</div><div class="photo_img">서로 편을 갈라 혐오하고, 국가 단위의 혐오도 있다.</div><div class="photo_img">물론 그 모든 것들이 근거 없는 혐오는 아니겠지만.</div><div class="photo_img">많은 부분은 근거 없는 혐오라고 생각한다.</div><div class="photo_img"><br></div><div class="photo_img">혐오의 대상을 희화화해서 낄낄대는 소설이 유익한가.</div><div class="photo_img">우리들의 샤일록은 누구일까.</div>', '2024-07-27 17:00:42');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('bfb7dfb9-c4fb-4ae9-9f2d-b483c6976232', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'lyu328', '좀비즈 어웨이 - 배예람', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/cca6f5b8-fe35-4535-bc00-a1a889e118ed" data-image-index="0" alt="mosaejqlpg.jpeg" width="257"></div><div class="photo_img"><br></div>나는 품에 안은 공을 내려다보았다.<div class="photo_img"><br></div><div class="photo_img">그건 공이 아니었다. 3반 반장의 머리였다.</div><div class="photo_img"><br></div>', '2024-07-27 16:56:14');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f6cc0a2f-854b-4ab1-af61-0ad1b804cce6', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '변화하는 세계질서 - 레이 달리오', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/780e0d99-2114-40a1-923b-8b73981f3fb6" data-image-index="0" alt="mosalT5RK7.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">사회과학 논문을 책으로 펴낸 것.</div><div class="photo_img"><br></div><div class="photo_img">전 세계를 주름잡던 강대국들이 동일하게 상승했다가 하락하는 역사적 사실에서</div><div class="photo_img">공통적으로 어떤 요소들이 영향을 끼쳤고, 어떻게 변화하였는지를 적었다.</div><div class="photo_img"><br></div><div class="photo_img">분석 대상만큼 내용도 추상적이어서 엄밀성은 떨어져 보인다.</div><div class="photo_img"><br></div><div class="photo_img">그냥 이 사람은 이렇게 생각하는구나 읽어보면 좋겠다.</div>', '2024-06-29 12:30:23');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('957b44d4-0c86-4bc9-b347-2b95a737eef1', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yhg1803', '죽음의 수용소에서-빅터 프랭글', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/ea1231ce-1217-4f49-bfc9-415cf7af69c0" data-image-index="0" alt="mosag3KEMW.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">사람은 적응의 동물이다.</div><div class="photo_img"><br></div><div class="photo_img">군대 가서도 3일이면 적응하고, 아무리 힘든 일이나 어려운 상황에서도</div><div class="photo_img">무언가를 해내는 사람들이 있다.</div><div class="photo_img"><br></div><div class="photo_img">정신과 의사 빅터 프랭글은 아우슈비츠를 비롯해 나치 수용소 여러 곳을 거치며</div><div class="photo_img">자신의 마음이 어떻게 작동하는지, 어떻게 적응하고 변화했는지를 생생히 적었다.</div><div class="photo_img"><br></div><div class="photo_img">의지가 사람을 만들고, 이겨내게 한다.</div>', '2024-06-29 12:23:18');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('3cd86cb3-f679-4f6b-b6e5-83c8c6f249df', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '구의 증명 - 최진영', '읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;<div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/f0f36fa9-efe1-47a1-a862-54dbb168d1b0" data-image-index="0" alt="mosaTIumiV.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">구는 담이 없는 세상에서 살기위해 증명해야만 했다.&nbsp;</div><div class="photo_img">맞고 틀리고는 중요하지 않았다.&nbsp;</div><div class="photo_img">해야만 했다.&nbsp;</div><div class="photo_img"><br></div><br></div>', '2024-06-29 12:23:13');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('b4040c06-b3d6-40d1-896c-575d17d42609', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '단 한 사람 - 최진영', '읽었던 책들 중에 추천하고 싶은 책이 있다면 소개 해 주세요 &#39;-&#39;<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/9e1a11df-09fd-4163-81a1-f362ca05993a" data-image-index="0" alt="mosajzLoL1.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">임천자의 단 한 사람은 기적</div><div class="photo_img">장미수의&nbsp;단 한 사람은 겨우</div><div class="photo_img">신목화의&nbsp;단 한 사람은 단 한 사람을 살리는 일</div><div class="photo_img">나의&nbsp;단 한 사람은 공감</div><br></div>', '2024-06-29 12:22:13');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('9295f744-dca9-41ee-84dd-c6a66ad6b629', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '지나치게 연결된 사회 - 마르쿠스 가브리엘', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/b7a28f7c-deaf-4a12-819c-b1bca3bcb1cf" data-image-index="0" alt="mosaypalgH.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">어디서 본 것 같은 젊은 꼰대 철학자가 한땀한땀</div><div class="photo_img">수놓은 한정판 보따리</div><br></div>', '2024-06-29 12:20:34');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('4b446f4f-d900-4d79-a549-00acb66fd051', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '생각 중독 - 닉 트렌턴', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/685429ec-0eb5-4a62-96fc-a6c20ca9aea9" data-image-index="0" alt="mosahqdhMg.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">"걱정을 해서 걱정이 없어지면 걱정이 없겠네."</div><div class="photo_img"><br></div><div class="photo_img">꼬리에 꼬리를 무는 생각들로&nbsp;잠 못 이루는 셀프 고생 성격을&nbsp;뜯어 고치고 싶어서 읽었습니다.</div><div class="photo_img">이 책을 읽으며 &#39;생각 일기&#39;를 적기&nbsp;시작했는데 하루의 생각을 정리하고 마침표를 찍는 느낌이라 좋습니다. ♥</div>', '2024-05-27 10:25:33');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('a781d51b-016c-4032-b63c-18ea80e193f8', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '세컨드 브레인 - 티아고 포르테', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/dd0cc8d5-33ee-4e7c-97b2-89b07f97ca17" data-image-index="0" alt="mosavJbvp8.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">사람이 옷을 입는 것이지</div><div class="photo_img">옷이 사람을 입는 것이 아니다.</div><div class="photo_img"><br></div><div class="photo_img">그래도 그러고 싶다면</div><div class="photo_img">생각보다 큰 각오가 필요하다.</div>', '2024-05-27 10:20:32');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('fc95af4d-8b68-4183-bb1f-04875f779b8e', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '학교 폭력 어떻게 만들어지는가 - 문재현', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/3fe4ac3d-eed3-4c3a-9853-e4f62ae61554" data-image-index="0" alt="mosaTcDjR1.jpeg" width="438"><br></div><div class="photo_img">어른들은 몰라요</div>', '2024-05-27 10:17:38');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f8ab28fa-8e67-47a0-a84d-41bb62c04a98', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '실력과 노력으로 성공했다는 당신에게 - 로버트 H. 프랭크', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/941e7bf3-45c1-4318-b558-5afcc35cefb8" data-image-index="0" alt="mosakV2WKF.jpeg" width="438">&nbsp;</div><div class="photo_img">&nbsp;6:3:1 </div>', '2024-05-27 10:16:25');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('8525e0f0-9083-4255-a876-1eff9a6c08d3', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '아빠가 나서면 아이가 다르다 - 정우열', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/9aa2f9ec-f195-4421-8789-842ca42b0f3d" data-image-index="0" alt="mosauT0L5x.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">아이는 저절로 크지 않는다,,</div>', '2024-05-27 10:13:31');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('23aaebf6-9e1d-41c7-9656-1a45b788e2df', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '아무리 잘해줘도 당신 곁에 남지 않는다 - 전미경', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/0019d863-0321-4c71-8097-1a3d5e1f7097" data-image-index="0" alt="mosahfv2ZM.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">어느 무리에 잡음 없이 속한다는 건,</div><div class="photo_img">나의 모습을 감추고 타인과 적절한 타협을 했을 때 가능하다.</div>', '2024-05-27 10:12:11');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('e07cec33-70b5-41a2-9692-58aed8dd2405', 0, true, false, 'HTML', '8a6b3cbe-bcdf-43bb-81a5-4aaca60cefc5', 'yasha_bread', '소소소-서윤후', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/3ae19a1f-1d23-4bf5-8eaf-1f2abf6c5ea8" data-image-index="0" alt="mosa7zpnfx.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;1. 여분의 삶</div><div class="photo_img">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;턱수염의 신</div><div class="photo_img">2. 미래지하입구</div><div class="photo_img">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 미래지하정전</div><div class="photo_img">&nbsp; &nbsp; &nbsp; &nbsp; 미래지하후기 - 인간도감과 X</div><div class="photo_img">&nbsp; &nbsp;- 시집 안에 또 다른 세계관</div>', '2024-05-12 15:13:34');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('9e5c3523-4f62-4cb6-a23c-17ba74db633f', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전문화재단] 2025년 생활문화 활성화지원 공모 신청', '안녕하세요.<div class="photo_img">대전포스트잇 모임장 서담입니다.</div><div class="photo_img"><br></div><div class="photo_img">홈페이지 이전 건으로 최근 모임 홈페이지 사용을 자제하고 있으나,</div><div class="photo_img">이번 대전문화재단 주관 지원사업 공모에 대한 자세한 계획 및 내용은</div><div class="photo_img">공지는 전체적으로 드려야 할 것 같아서 글을 썼습니다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">2025년 재단법인 대전문화재단</div><div class="photo_img">생활문화 지원사업 공모 내용</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">사업명 : 대전포스트잇 독서에 머물다</div><div class="photo_img"><br></div><div class="photo_img">대표자 : 서담</div><div class="photo_img"><br></div><div class="photo_img">주요 프로그램 :</div><div class="photo_img">1. 책에 머물다</div><div class="photo_img">&nbsp;ㄱ. 3월 정모 위치는 대전 동구 &#39;머물다가게&#39;에서 진행.&nbsp;</div><div class="photo_img">&nbsp;ㄴ. 단체 채팅방에서&nbsp; 사전에&nbsp;Key word를 정함.&nbsp;</div><div class="photo_img">&nbsp;ㄷ.&nbsp; 해당 주제에 맞는 책 한 권을 각자 선정. </div><div class="photo_img"><br></div><div class="photo_img">2. 같이 머물다</div><div class="photo_img">&nbsp;ㄱ. 6월 정모 위치는 대전 동구 &#39;머물다가게&#39;에서 진행.&nbsp;&nbsp;</div><div class="photo_img">&nbsp;ㄴ. 자신이 읽었던 책 (E-BOOK 제외) 중 하나를 선정.</div><div class="photo_img">&nbsp;ㄷ. 들고 온 책에 대한 담소 후,&nbsp; 모임원 간 책 교환.</div><div class="photo_img"><br></div><div class="photo_img">3. 작가와 머물다</div><div class="photo_img">&nbsp;ㄱ. 9월 정모 위치는 대전 동구 &#39;머물다가게&#39;에서 진행.&nbsp;</div><div class="photo_img">&nbsp;ㄴ. 사전에 협의 된 작가님의&nbsp;북토크 진행.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">* 3 가지의 주요 프로그램 중 독립적으로 선택 해주시면 됩니다.&nbsp;(중복 가능; ex. 1번만 선택 / 2번, 3번 선택 / 모두 선택)</div><div class="photo_img"><br></div><div class="photo_img">* 주요 프로그램 1종류 당 최대 인원은 선착순으로 10명입니다.</div><div class="photo_img"><br></div><div class="photo_img">* 참가비는 일체 지원되며, 참여 시 음료값은 별도입니다.</div><div class="photo_img"><br></div><div class="photo_img">* 일정은 상황에 따라 순서가 변경 될 수 있습니다.</div><div class="photo_img"><br></div><div class="photo_img">* 신청서의 자세한 내용은 단체 채팅방의 우측 상단 메뉴바의 파일명 &#39;붙임 1-1. 생활문화 활성화지원 지원신청서_대전포스트잇_게시ver.&#39; 에서 확인 가능합니다.</div>', '2025-02-14 22:58:05');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('a01baaef-5848-453c-b48d-82ddd98f258f', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전포스트잇] 2024년 책꽂이 정산 결과 및 2025년도 홈페이지 재오픈 안내', '<div class="photo_img">안녕하세요. 서담 입니다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">즐거운 소식 하나와 슬픈 소식 하나를 가져 왔습니다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">일단 먼저 즐거운 소식 하나 !</div><div class="photo_img"><br></div><div class="photo_img">2024년도 책꽂이 정산이 예정 되어 있다고 오픈 카톡방에 간단하게 공지를 드렸었는데요,</div><div class="photo_img">먼저, 아래 스크린 샷에서 확인 가능하듯 관리자 외 1등과 2등이신 dbst*, yhg1* 각 2 표씩</div><div class="photo_img">그리고 책꽂이에 1번이라도 참여해 주신 분은 1 표 씩 부여하여 총 15개의 사다리 뽑기를 진행했습니다.</div><div class="photo_img"><br></div><div class="photo_img">정모에 많은 사람들이 모였을 때 진행하면 더 재밌을 것 같기도 하였지만,</div><div class="photo_img">연말 연초에 다들 바쁘시기도 하고 처음 진행하는 거라 파일럿 겸&nbsp;혼자 진행하였습니다.</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/3ff7e6e4-f598-4f0c-9b52-79764593144b" data-image-index="0" alt="mosaIeEzHp.png" width="438"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/c5619aa3-1c91-400a-85ea-b01c2adb04fb" data-image-index="1" alt="mosav7i5lb.png" width="438"></div><div class="photo_img"><br></div><div class="photo_img">당첨되신 sias*,&nbsp; iamd* 님 두 분 먼저 축하 드립니다.</div><div class="photo_img">상품은 제가 지난 주 파타르 프로젝트 북페어에서 구매한 책 두 권을 드릴 예정입니다.</div><div class="photo_img"><br></div><div class="photo_img">아스타 (*) 처리로 인해 오픈채팅 닉네임과 연결이 되지 않기 때문에, 당첨되신 분은 꼭 확인 하시고</div><div class="photo_img">오픈 채팅방에서 얘기주시면 자유 독서 모임 때나 정기 모임 때 직접 드리겠습니다.</div><div class="photo_img"><br></div><div class="photo_img">다시 한 번 뽑히신 두 분 축하 드립니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">슬픈 소식으로는 홈페이지 이전 입니다.</div><div class="photo_img">이전하게 된 계기는 NAVER&nbsp; MODOO라는 플랫폼이 더 이상 서비스를 하지 않겠다고 공지를 받았기 때문입니다.</div><div class="photo_img">1월부터 추가 신규 홈페이지는 생성이 불가 하며, 기존의 홈페이지의 경우 새로운 게시판 및 서비스 항목 추가에는 제한되며</div><div class="photo_img">이듬해 6월부터는 NAVER MODOO서비스 종료로 인하여 기존 홈페이지 또한 이용이 불가능 합니다.</div><div class="photo_img"><br></div><div class="photo_img">따라서 현재 홈페이지가 가지고 있는 여러 장점들이 유지되는 다른 플랫폼을 찾는 대로 이전 준비 중 입니다.</div><div class="photo_img">가까운 시간 내로 이전 준비가 끝내어 공지를 통해 또 찾아 뵙겠습니다.</div><div class="photo_img"><br></div><div class="photo_img">모두 즐거운 한 해 시작 하시길 바랍니다 !&nbsp; &nbsp;&#39;-&#39;</div>', '2025-01-02 00:00:24');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('3f489202-82ed-4b5a-9cb0-3deeb6ce8145', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전포스트잇] 2024년도 책꽂이 정산', '안녕하세요, 서담입니다.<div class="photo_img"><br><div class="photo_img">&nbsp;올해 봄, 꽃이 한창일 무렵 모임을 시작해 벌써 다음 해를 준비하게 되었습니다.</div><div class="photo_img">&nbsp;운영해 오면서 아쉬움도 뿌듯함도 많은 감정들이 지나간 해였네요.</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;이대로 떠나보내기엔 아쉬운 마음에 저희 모임활동의 결과물 중 하나인 책꽂이 정산을 하고 모임활동에 참여 해 주신 분들께 감사를 표하고자 합니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;그 동안 정모에 참여하시거나 개인적으로 게시해주신 책꽂이의 글을 활용하여 두 분을 선정하여 소정의 상품을 드리고자 합니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;자세한 내용은 단체 카톡방에서 얘기 드리겠습니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">&nbsp;많은 관심 부탁 드립니다 &#39;-&#39;&nbsp;</div></div>', '2024-12-20 10:51:20');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('1de1781e-9285-4651-b177-edcf2a41ba58', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 북토크-과학자의 발상법', '<div class="photo_img">희망의책대전본부 작가초청 열번째 북토크!!</div><div class="photo_img"><br></div><div class="photo_img">&lt;이종필&gt; 교수 초청 "과학자의 발상법"!!</div><div class="photo_img">인공지능시대를 어떻게 살아갈 것인가에 대한 가장 강력한 무기를 담아내었습니다!!</div><div class="photo_img"><br></div><div class="photo_img">- 일시 : 2024. 12. 27(금) 저녁 7시</div><div class="photo_img">- 장소 : 대전지식산업센터 602호</div><div class="photo_img">- 신청 : https://bit.ly/과학자의발상법</div><div class="photo_img"><br></div><div class="photo_img">&lt;책소개&gt;</div><div class="photo_img">교양과학서와 일간지 칼럼 등을 통해 오랜 시간 대중과 소통해온 물리학자 이종필 교수의 신작. 저자는 지난 20여 년간 물리학을 연구하고 교육하면서 과학의 역사 속 위대한 발견을 이끈 과학자의 생각법에 각별한 관심을 갖고 탐구해왔고, 이를 마침내 6가지 발상법으로 정리해냈다. 정량적 발상부터 보수적/혁명적 발상, 실용적/미학적 발상까지, 과학자들의 생각법이 어떻게 지식의 도약과 패러다임 전환을 끌어왔는지를 차근차근 살펴본다.</div><div class="photo_img"><br></div><div class="photo_img">독자들은 과학사 속 지식의 생산 과정을 두루 살펴볼 수 있을 뿐 아니라, 과학자의 생각법에 초점을 맞추어 새로운 관점으로 과학사와 그 지식을 정리해볼 수 있다. 과학자의 사고 전략이 궁금한 이들과 과학자를 꿈꾸는 이들에게 이 책은 최고의 선물이 될 것이다.</div><div class="photo_img">_ 출처: 알라딘</div><div class="photo_img"><br></div><div class="photo_img">&lt;저자소개&gt;</div><div class="photo_img">1971년 부산에서 태어났다. 현재 건국대학교 상허교양대학 교수로 재직 중이며, 물리학자이자 과학 커뮤니케이터로 활동 중이다. 서울대학교 물리학과를 졸업하고 같은 대학원에서 입자 물리학으로 박사학위를 받았다. 한국과학기술원KAIST 부설 고등과학원KIAS, 연세대학교, 서울과학기술대학교에서 연구원으로, 고려대학교에서 연구교수로 재직했다.</div><div class="photo_img">2016년 건국대학교에 교양대학이 처음 생길 때 교수로 부임하면서 학생들에게 교양으로서 과학을 어떻게 가르쳐야 할 것인가를 고민했으며, 가장 기본적인 출발점으로서 대학생들이 꼭 읽어야 할 좋은 책들을 선정하고자 했다. 더불어 이에 대한 길잡이 안내서를 만든다면, 이 책을 중심으로 관련된 주제들의 그물망을 만들고 자연스럽게 학문의 지형도를 구축할 수 있으리라 생각했다. 저자의 이 오랜 고민을 담아 《세계 물리학 필독서 30》을 집필하게 되었다. 꼭 해야만 하는 오랜 숙제를 시작하는 마음으로, 또한 언젠가 실행할 과업의 출발점이 될 책을 만든다는 마음으로 이 책을 써냈다.</div><div class="photo_img">저서로 《샐러리맨, 아인슈타인 되기 프로젝트》 《우리의 태도가 과학적일 때》 《신의 입자를 찾아서》 《이종필 교수의 인터스텔라》 《물리학 클래식》 등이 있고, 번역서로 《물리의 정석》 시리즈, 《그림으로 보는 모든 순간의 과학》 《블랙홀 전쟁》 《최종 이론의 꿈》 등이 있다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">- 최근작 : &lt;세계 물리학 필독서 30&gt;,&lt;과학자의 발상법&gt;,&lt;물리학, 쿼크에서 우주까지&gt; … 총 50종</div><div class="photo_img"><br></div><div class="photo_img">**2024년 대전시지방보조금사업입니다.<div class="photo_img"><img src="http://localhost:8080/api/attachments/843a4dff-1720-485b-ab0d-5d8703e69f4b" data-image-index="0" alt="mosaOpQP3m.png" width="257"></div></div>', '2024-12-16 12:40:18');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('d2f580c9-0b1b-4b61-a485-a9aedab19e58', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[파타르 프로젝트] 팝업 북마켓&재즈공연', '<div class="photo_img">안녕하세요~</div><div class="photo_img">파타르 프로젝트라는 팀에서 문화 행사에 대하여 홍보차 연락이 와서 모임원분들께 공유 드립니다.</div><div class="photo_img">아래 내용은 이번 &#39;팝업 북마켓&amp;재즈공연&#39;에 대한 소개 내용을 간략히 정리하였습니다.</div><div class="photo_img"><br></div><div class="photo_img">관심 있으신 분들은 읽어봐 주시고 궁금한 내용이 있다면 언제든지 단체 카톡방에서 얘기주세요.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">안녕하세요 :)&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">대전에서 ‘파타르 프로젝트’ 팀 이름으로,</div><div class="photo_img">팝업 북마켓&amp;재즈공연을 만들어가고 있습니다.</div><div class="photo_img"><br></div><div class="photo_img">관심이 있을 만한 분들이 누리고 가셨으면 하는 마음에 대전에서 책,독서로 모이시는 분들께 소식을 전하고 싶습니다.</div><div class="photo_img"><br></div><div class="photo_img">/</div><div class="photo_img"><br></div><div class="photo_img">12월 28일 토요일, 대전 대동역 근처의 어느 작은 창고에서,</div><div class="photo_img">낮에는 11팀의 작가님들의 북마켓(프리), 저녁에는 재즈공연(티켓팅)이 있습니다.</div><div class="photo_img"><br></div><div class="photo_img">작가님들은 그림책, 아트북, 소설, 에세이 등 다양한 라인업으로 구성되어 있습니다.</div><div class="photo_img">책방, 디자인스튜디오, 출판사, 작가 등이 직접 참여하여 작가님들과 직접 소통할 수 있는 자리이기도 합니다.</div><div class="photo_img"><br></div><div class="photo_img">저희가 행사를 위해 직접 공간을 인테리어 공사하여 따듯한 시간을 선물 드리고자 합니다.</div><div class="photo_img"><br></div><div class="photo_img">연말에 모두에게 선물을 드리고자 하는 마음으로 기획하게 된 프로젝트인 만큼, 이익 수단으로 펼쳐지는 공간이 아닙니다.</div><div class="photo_img"><br></div><div class="photo_img">감사합니다.☺️&#x1f64f;&#x1f3fb;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">//</div><div class="photo_img"><br></div><div class="photo_img">아래 링크를 통해 라인업 및 행사 모든 일정에 대해 파악하실 수 있습니다.</div><div class="photo_img"><br></div><div class="photo_img">&#x1f388;12월 28일 ‘북마켓&amp;재즈공연’ 안내링크</div><div class="photo_img"><br></div><div class="photo_img">https://patar-episode.notion.site/Patar-project-ep-1-Holiday-book-fair-Jazz-night-1411deff011c80cbb6ccd9beed50ec83#1421deff011c805bbf9dd374e9aa3c70</div><div class="photo_img"><br></div><div class="photo_img">* 안내 링크 페이지 안에 재즈공연 예매 (구글폼) 진행이 가능합니다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">&#x1f388;파타르프로젝트 sns계정</div><div class="photo_img"><br></div><div class="photo_img">www.instagram.com/patar.episode</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">#대전독서모임 #대전포스트잇 #파타르프로젝트</div>', '2024-12-13 13:30:12');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('e49456c8-5d28-4a5f-84d5-3cd26ecb0e2b', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[한국직업능력진흥원] 자격증 취득 스터디', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/351a2749-1d9a-496c-b39f-fd69992decea" data-image-index="0" alt="mosayxvVSk.png" width="438"></div>안녕하세요 ^^</div><div class="photo_img">개인적인 목표로 내년인 2025년에 자격증 취득을 계획 중에 같이 하실 모임원 분들이 있으실까 싶어서 공유 드립니다.</div><div class="photo_img"><br></div><div class="photo_img">다 같이 똑같은 걸 하진 않겠지만, 각자 준비 중인 자격증 내용이나 진도를 공유하면 동기부여도 생길 것 같습니다 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img">하실 분들은 밑의 링크를 따라 홈페이지 회원 가입하시면 1인당 3개의 자격증 수강에 한해 무료 수강 신청을 할 수 있다고 합니다.</div><div class="photo_img"><br></div><div class="photo_img">둘 중 편한 곳으로 고르시면 될 것 같습니다~&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">https://www.pqi.kr/index</div> 한국직업능력진흥원 자격증 공식 교육기관 한국직업능력원격평생교육원<div class="photo_img"><br><div class="photo_img">https://www.korea-edu.net/</div><div class="photo_img"> 한국자격검정평가진흥원｜공식발급 자격증 교육기관 <br></div></div>', '2024-12-04 17:06:45');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('fcbaa7dd-61f0-407f-b7c0-9c5183dfdf92', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[한밭도서관] 평일 독서 특강', '<div class="photo_img">한밭도서관 독서특강</div><div class="photo_img">&lt;칼 세이건의 ‘코스모스’ 읽기&gt;</div><div class="photo_img">일시: 12월 10일(화) 저녁 7시~</div><div class="photo_img">장소: 한밭도서관 제2자료실</div><div class="photo_img">강사: 윤성철 교수 (서울대학교 물리천문학부)</div><div class="photo_img">대상: 코스모스를 읽은 사람, 코스모스를 읽을 사람</div><div class="photo_img">모집: 대전시OK예약서비스</div><div class="photo_img">https://www.daejeon.go.kr/okr2019/eduRsvtList.do?menuSeq=8101&amp;ntatcDelYn=Y&amp;boardUseYn=N&amp;menuUseYn=N</div><div class="photo_img">문의: 자료운영과 (270-7487)</div><div class="photo_img">&lt;새해 작심독서 프로젝트&gt; 내년 1월부터 벽돌책 ‘코스모스’를 읽고 싶은 분들을 모집 예정입니다</div>', '2024-12-04 14:07:58');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('f276bd7e-0ece-4c0c-829d-0725cd98a30a', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[유성문화원[ 2024 인문학콘서트 10회차 ‘나이듦에 대하여’', '<p><div class="photo_img"><img src="http://localhost:8080/api/attachments/63510b65-9816-4844-b895-4f8da7af9ea3" data-image-index="0" alt="mosacj5ed4.jpeg" width="438"></div></p><p>&nbsp;</p><p>한 해를 돌아보는&nbsp;2024년 연말,</p><p>소중한&nbsp;‘나’를 돌아보는 시간은 어떠신가요?</p><p>&nbsp;</p><p>신경심리학 박사가 전하는</p><p>따뜻한 위로와 잊었던&nbsp;‘나’를 마주하는 시간.</p><p>그리고 나의&nbsp;‘나이듦’에 대하여.</p><p>&nbsp;</p><p>2025년을 준비하는 소중한 시간이&nbsp;되시길 바랍니다. ^^</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>&nbsp;</p><p>ㅇ&nbsp;일 시: 2024. 12. 13.(금)&nbsp;오후&nbsp;7시</p><p>&nbsp;</p><p>ㅇ&nbsp;장 소:&nbsp;유성문화원&nbsp;2층 다목적실</p><p>&nbsp;</p><p>ㅇ&nbsp;강 사:&nbsp;윤정애&nbsp;/&nbsp;신경심리학박사,&nbsp;마인드앤바디브릿지코리아대표,&nbsp;전)대전보건대 교수, 저서 &lt;공황장애가 내게 가르쳐준 것들&gt; 등.&nbsp;</p><p>&nbsp;</p><p>ㅇ&nbsp;​신청 및 문의:&nbsp;</p><p>- 포스터 QR코드</p><p>- 유성문화원 사무국 042-823-3915</p><p>- https://naver.me/GTechQM5</p>', '2024-12-02 09:59:11');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('dcee2680-0438-43f3-99a6-a94e01895335', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 여덟번째 북토크 소년식물기', '안녕하세요 ^^ 희망의책 대전본부 입니다.&nbsp;<div class="photo_img">가을에 들어설 때 시작한 북토크가 벌써 여덟번째를 맞이합니다!!&nbsp;</div><div class="photo_img">여덟번째 북토크책은 소년의 식물기 입니다. 무려 11월 1일에 발간된 아주 따끈따근한 신작인데요 ^^</div><div class="photo_img">이상권작가님과 함께하는 북토크에 많은 참여와 관심 바랍니다.&nbsp;</div><div class="photo_img">- 일시 : 2024. 11.28(목) 저녁 7시</div><div class="photo_img">- 장소 : 강스튜디오(전민동 61번길, 8)</div><div class="photo_img">- 신청 : https://bit.ly/소년의식물기</div><div class="photo_img"><br></div><div class="photo_img">&lt;책소개&gt;</div><div class="photo_img">자연을 그리는 화가가 되고 싶었던 아홉 살 소년은 어느 날 커다란 암소 한 마리를 책임지게 되었고, 그때부터 소가 좋아할 만한 풀들을 찾아다니며 숲에서 뒹굴었다. 우연히 파브르의 어린 시절을 그린 만화를 보고는 과학자가 되리라 포부를 다지지만, 현실과 이상 사이에서 꿈을 포기한다는 것이 무슨 의미인지를 한순간에 깨닫고 마는데….</div><div class="photo_img"><br></div><div class="photo_img">풀꽃과 동물의 삶과 생명의 힘을 문학에 담아 온 작가 이상권의 신작 논픽션 『소년의 식물기』가 출간된다. 1994년 《창작과 비평》에 소설을 발표한 후 지금까지 다양한 장르에서 필력을 자랑한 작가는 『풀꽃과 친구가 되었어요』 등의 동화뿐만 아니라 『시간 전달자』로 대표되는 청소년 소설, 『애벌레를 사랑한 애벌레』『들꽃의 살아가는 힘을 믿는다』 같은 생태 논픽션을 출간했다. 그중 소설 『고양이가 기른 다람쥐』는 현재 고1 국어 교과서에 수록되어 있다. 『소년의 식물기』는 모두 16개의 장으로 구성되어 있으며, 글과 함께 작가가 직접 그린 식물 그림 40컷과, 그의 딸 이단후의 그림 136컷 등이 수록되어 자연과학적 지식을 이해하는 데 도움을 줄 뿐만 아니라 동화적 감성까지 두루 선사한다. 작가는 이 책에 “식물이란 자급자족하는 유일한 생명, 그러니까 가장 완벽한 존재라는 사실”임을 깨달은 계기가 되는 사건과 이야기 들을 엄선해 담았다. 또한 ‘머리 아홉 달린 괴물’ 같은 옛 이야기뿐 아니라 작가가 어릴 때 직접 경험한 에피소드들이 마치 동화처럼 ‘소년’의 이야기로 그려진다. 자연과 생명에 대한 애착은 소년이 가난과 아버지의 부재를 이겨내게 해주었고, 작가로서의 삶을 일구는 중심축이 되어주었다.</div><div class="photo_img"><br></div><div class="photo_img">작가는 영원한 목숨을 가진 ‘히드라’의 삶에서 이야기를 시작하는데, 이는 파브르에 대한 오마주로 해석된다. 죽었다가 살아나는 동물 이야기를 듣고 아버지를 되살리고 싶었던 여덟 살 아이로 돌아가 유한한 인간 생명에 대한 경험을 털어놓는다. 꼬리가 잘려도 다시 자라는 도마뱀과 달리, 손가락이 잘려도 다시 자라지 않는 동네 형의 기억 역시 어린 소년의 가슴에 깊이 박혀 있다. 이러한 소년의 체험들은 어린눈의 탄생부터 땅속에 단단한 터전을 일구는 뿌리, 나무의 몸으로서 중심을 잡는 줄기, 영양분을 비축하는 열매, 식물의 구조 및 변화 등의 과학적 원리와 함께 어우러져 소년의 기쁨과 고통, 설렘과 모험 같은 성장의 기록을 독자가 간접적으로 경험할 수 있게 한다. “완벽한 존재란 누군가를 지배하거나 착취하는 시간을 사는 게 아니라 타자를 존중하고 같이 살아가는 철학적인 힘을 가진 생명”임을 일깨우는 이 책은, 평생을 한곳에서 살아가는 식물들처럼 뿌리를 튼실하게 하며 자기 삶을 충실히 살아가는 것, 다른 존재와 어울려 사는 것의 중요성을 이야기한다. 스쳐 지나가는 풀잎 한 자락에도 인간이 배워야 할 점이 있다는 사실을 깨닫는다면 결국 세상과 조화를 이루며 영원을 배울 수 있으리라 가르쳐준다. * 출처 : 예스24</div><div class="photo_img"><br></div><div class="photo_img">&lt;작가소개&gt;</div><div class="photo_img">한양대학교에서 문학을 공부했다. ≪창작과 비평≫에 소설을 발표하면서 작가가 되었고, 30년 넘게 글만 쓰는 예술가의 시간을 걸어왔다. 문학책보다 과학책을 더 많이 읽는다. 인간이 잃어버린 생명의 언어를 문학으로 해독하고 소통하는 글을 쓰고자 한다. 작품으로는 『위로하는 애벌레』, 『애벌레를 위하여』, 『1점 때문에』, 『족제비의 안타까운 복수』, 『서울 사는 외계인들』, 『시간 전달자』 등이 있다. 소설 『고양이가 기른 다람쥐』가 고1 국어 교과서에 수록되었으며, 『하늘로 날아간 집오리』를 비롯하여 10여 권의 책이 프랑스어, 영어, 일어, 중국어, 스페인어 등으로 번역, 출간되었다. * 출처 : 예스24</div>', '2024-11-20 19:32:56');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('a8da37d6-b9c7-451a-a182-4565cacab933', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전광역시] 2024북페어', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/4564db2f-5c47-4ee5-928a-cc4fbc1dc130" data-image-index="0" alt="mosaoRVE3l.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">북페어 열린다구 하네요 ㅎㅎ</div><div class="photo_img">관심있으신분들은 참고하셔요 ㅎㅎ</div>', '2024-11-16 14:52:03');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('620b44ae-c0d6-4bea-9ada-590588c01478', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전시립예술단] 화목한 문화산책', '<p>    </p><div class="photo_img"></div><p>□ 대전시립예술단은 이달 12일부터 2주간에 걸쳐 화요일과 목요일 오후 7시 30분에 유성구 한밭대학교 아트홀에서 시민을 위한 ‘화목한 문화 산책’공연을 연다.</p><p>  &nbsp;  </p><p>ㅇ 우리 동네 문화 가꾸기’로 2014년 시작해 올해 11년째 접어든‘화목한 문화산책’은 시민들의 문화 향유와 도심 활성화에 기여하며 많은 사랑을 받아온 시립예술단 공연이다.</p><p>  &nbsp;  </p><p>ㅇ 이번 공연은 지난 4월 대덕구, 6월 동구, 10월 중구에 이어 올해 마지막 공연으로 한밭대학교로 찾아가 시민들에게 삶의 기쁨과 여유를 선사할 것이다. </p><p>  &nbsp;  </p><p>□ 첫 번째 날인 12일 시립교향악단은 피아니스트 최유미의 협연으로 그리그 ‘피아노협주곡 1악장’을 준비했다. 또한 세련된 무대 매너와 안정된 연기력으로 활발한 방송, 공연 활동을 보여주고 있는 뮤지컬배우 정영주의 웨버 ‘오페라의 유령’, 카푸아 ‘오 나의 태양’ 등을 감상할 수 있다. </p><p>  &nbsp;  </p><p>ㅇ 14일에는 시립합창단과 어쿠스틱 밴드 ‘자전거 탄 풍경’이 전하는 추억의 음악 여행이 펼쳐진다. ‘푸니쿨리 푸니쿨라’,‘성자들의 행진’ 등 우리 귀에 익숙한 합창음악과 대한민국 포크록을 대표하는 3인조 밴드 자전거 탄 풍경의 연주로 ‘너에게 난, 나에게 넌’,‘보물’ 등의 노래를 감상할 수 있다. </p><p>  &nbsp;  </p><p>ㅇ 19일은 시립연정국악단의 무대로‘남도아리랑’,‘세계민요기행’,‘토리이야기’등과 ‘신모듬 3악장 놀이’의 신명나는 사물놀이 협주로 쉴 틈 없이 흥겨운 무대를 펼친다. 또한 객원지휘자 박상우와 가수 강태관의 협연으로 ‘한오백년’,‘코뿔소’ 등의 노래를 만나볼 수 있다. </p><p>  &nbsp;  </p><p>ㅇ 21일에는 어린이들로부터 많은 인기를 얻고 있는 시립무용단의 춤으로 그리는 동화‘옹고집전’공연을 준비했다. 언제나 전석 매진을 기록하는 공연으로 익살스러운 안무와 동화 속을 옮겨놓은 듯한 무대와 영상 그리고 아이들의 귀에 쏙쏙 들어오는 재미있는 동화구연으로 어린이들에게 꿈과 희망을 안겨줄 예정이다. </p><p>  &nbsp;  </p><p>ㅇ 공연은 선착순 입장이며 전석 무료로 관람할 수 있다. 자세한 내용은 대전시립예술단 홈페이지(www.artdj.kr)와 예술단 공연사업지원국(☎ 042-270-8332)으로 문의하면 된다.</p><div class="photo_img"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/3a9a98e6-2dc3-4a53-ac8e-9ef6f83bce6a" data-image-index="0" alt="mosa7Vcsau.png" width="438"></div>', '2024-11-11 16:12:50');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('8390f4bc-c423-454f-a129-1ce8629b9422', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전문화재단] 대전포스트잇 동호회 등록', '안녕하세요 &#39;-&#39;<div class="photo_img">이번에 간단하게 알려드릴 소식이 있어서 글을 씁니다.</div><div class="photo_img"><br></div><div class="photo_img">최근 정기모임을 하는 중구 카페에이블을 통해 알게 된&nbsp;대전문화재단에<br>동호회 등록을 하였습니다.</div><div class="photo_img"><br></div><div class="photo_img">앞으로 또 하나의 플랫폼에서 모임 홍보를 할 수 있게 됐네요 ㅎㅎ</div><div class="photo_img">궁금하신 분들은 한 번 가보셔요~</div><div class="photo_img"><br><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/f678e3b6-9443-4176-92bd-00d07d63c747" data-image-index="0" alt="mosaKWvjfC.png" width="438"></div></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">#대전문화재단_생활문화포털 <br></div></div></div></div>', '2024-11-04 13:06:49');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('54ff10c3-df32-47ad-a1fd-6d723893171d', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[유성문화원] 11월 12월 인문학 콘서트 일정', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/264883d7-4668-466c-b451-df63426931ac" data-image-index="0" alt="mosawa1SzZ.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">내용은 중복이겠지만</div><div class="photo_img">11월 12월 하루씩 일정이 있기 때문에</div><div class="photo_img">간략하게 재공지 드립니다&#39;-&#39;&nbsp;</div>', '2024-11-02 19:50:28');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('d1bbb2f8-b157-4b91-9f06-b8d3c56fef10', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 여섯 번째 북토크 <박경순 작가>와 함께하는 "새로쓰는 고구려역사"', '<div class="photo_img">안녕하세요, 희망의책입니다. ^^</div><div class="photo_img">10월 숨가쁜 일정을 마치고 어느새 11월이 코앞입니다.&nbsp;</div><div class="photo_img">박경순 작가와 함께하는 희망의책 대전본부 여섯번째 북토크&nbsp; &lt;&lt;새로 쓰는 고구려 역사&gt;&gt; 에 준비했습니다.</div><div class="photo_img">* 2024. 11. 2(토) 오후 2시 / 지식산업센터 602호</div><div class="photo_img">*신청 : https://bit.ly/고구려</div><div class="photo_img"><br></div><div class="photo_img">&lt;&lt;작가소개&gt;&gt;</div><div class="photo_img">남북역사문화교류협회 교육위원장 1956년 전라북도 임실 출생. 1977년 서울대 동양사학과 입학. 청년시절 학생운동, 노동운동에 투신. 1998년 영남위원회 사건으로 구속. 2008년 민주노동당 부설 새세상연구소 부소장. 2012년 통합진보당 부설 진보정책연구원 부원장.</div><div class="photo_img">&nbsp;저서로는 『새로 쓰는 고조선 역사』, 『새로 쓰는 고구려 역사』, 『1930년대 이후 항일무장투쟁 연구1·2』, 『현대 조선의 역사』, 『현대 조선의 역사』,『김정은 시대 연구 1,2』,『북에서 바라본 우리 근대사』 등</div><div class="photo_img"><br></div><div class="photo_img"> <img src="http://localhost:8080/api/attachments/6284b4f4-a362-421e-ae2e-40f76e7aa063" data-image-index="0" alt="mosavKnbcq.png" width="438"> <br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">&lt;&lt;책소개&gt;&gt;&nbsp;</div><div class="photo_img">우리 역사 바로 보기로 잃어버린 호연지기를 되찾는다.</div><div class="photo_img"><br></div><div class="photo_img">이 책의 목표는 ‘우리 역사 바로 보기’다. 일제 강점기에 시작된 역사 왜곡은 해방 이후 지금까지 이어지면서 우리 민족의 위대한 역사를 ‘반도’의 역사에 머물게 하고 있다.&nbsp;『새로 쓰는 고구려 역사』는 동아시아 최대 강대국이었던 고구려의 광대한 영토와 역사에 대한 정확한 인식을 통해 우리 민족 고유의 호연지기를 되찾을 수 있도록 해줄 것이다.</div><div class="photo_img"><br></div><div class="photo_img">동아시아 최대 강대국 고구려사의 재발견으로&nbsp;분단사학을 극복하고 통일사학의 토대를 닦는다.&nbsp;고구려는 동아시아 최대 강대국이자 정치, 군사, 경제, 문화 등 모든 면에서 선진적인 나라로서, 우리 민족의 역사발전을 주도했으며 우리 민족의 자주권을 고수하고 민족의 영광을 널리 빛냈다. 그런데 국내외적으로 고구려의 역사에 대한 오해와 곡해가 많이 존재하며, 심지어 극심하게 왜곡하기도 한다. 특히 중국은 고구려의 역사를 자기 나라 역사에 편입시키는 동북공정을 진행하고 있다. 이러한 시기에 남과 북의 역사학계가 하나로 뭉쳐 고구려사를 우리 민족사의 기둥으로 우뚝 세워야 한다. 하지만 고구려 역사에 대한 남북 역사학계의 견해의 차이가 너무 커서, 다른 나라 역사학계의 고구려 역사 왜곡 폄하에 대한 공동대응이 어렵다.</div><div class="photo_img"><br></div><div class="photo_img">현재 고구려 역사에 대한 남북 사이의 쟁점은 건국 연대 문제, 국가 성격 문제, 평양지역 낙랑문화의 성격 문제, 고구려-수 전쟁과 고구려?당 전쟁의 위치 문제, 선행국가 구려국의 존재 유무 등 매우 광범위하다. 그동안 남북 사이의 단절과 소통 부재로 북측 역사학계의 연구 성과들이 남측 대중들에게 거의 전달되지 못했다. 이 책은 주관적 판단과 평가를 최대한 절제하고 북측 역사학계의 고구려사 연구 성과들을 있는 그대로 전달하려고 노력했다. 이로써 남과 북의 연구 업적들을 하나로 모아 고구려의 바른 역사를 되살려낼 수 있을 것이다.<div class="photo_img"><br></div></div>', '2024-10-30 10:21:42');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('530d0383-3853-4329-989f-ac63cd5bd5a5', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전예술가의집/대전엑스포시민광장 등 11 전시장] 2024 대전국제 사진축제', '<div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><p> <img src="http://localhost:8080/api/attachments/4da63884-4583-49c6-a83d-46156ae9d470" data-image-index="0" alt="mosapTHpUv.png" width="438"><br> <br></p><p><br></p><p>대전에서 충청권 최초로 열리는 ‘대전국제사진축제’는&nbsp;</p><p><br></p><p>사진예술을 사랑하는 사진가 뿐 아니라 대전시민과 국민, 모든 지구인들을 위한 특별한 축제가 될 것입니다. 수많은 세상사를 담을 수 있는 사진이라는 매개체를 통해, 서로의 문화와 경험을 공유하고 시각을 확장하는 기회를 마련하겠습니다.</p><p><br></p><p>이를 위해 대전국제사진축제는 매년 선정된 주제를 빛내줄 국내외 사진가들이 생성한 이미지 언어를 전달하고, 관람객들과 함께 열정과 감동을 나눌 수 있는 플랫폼을 만들 것입니다. 또한, 유망 작가 발굴을 위한 포트폴리오 리뷰와 그들이 펼쳐내는 ‘디스커버리전’은 신선한 시각적 결과물을 전달할 것입니다.&nbsp;</p><p><br></p><p>동물, 특히 반려동물은 우리에게 행복감과 안정감을 선사합니다. 이제는 우리의 삶에 중요한 동반자 역할을 하는 반려동물의 일상과 순간, 인간과의 유대를 담은 사진은 훌륭한 기록물이며 우리의 삶을 한층 풍요롭게 할 것입니다. 이러한 순간의 다양하고 재미있는 사진을 공모해 함께 공유하고 반추하려 합니다.</p><p><br></p><p>대전국제사진축제는 단순한 사진 전시를 넘어 지역과 국민, 세계와의 소통을 강화하고 사진이 지닌 강력한 힘과 아름다움을 함께 나누려합니다. 그래서 모든 이들이 기억에 남을 순간을 경험할 수 있도록 최선을 다할 것입니다.</p><p><br></p><p>여러분의 많은 관심과 참여를 부탁드리며, 11월 대전에서 뵙겠습니다.</p></div></div></div></div></div></div></div><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"></div></div></div></div></div></div><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><p>대전국제사진축제 조직위원장 &nbsp; &nbsp;전재홍</p><p><br></p><p><br></p><p><br></p><p>[주제전]</p><p> </p><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><p>올해의 주제전은 다양한 시대와 장소에서 촬영된 국내외 다큐멘터리 사진들로 구성되며, 각각의 사진이 어떠한 방식으로 현실을 기록하고 표현하고 있는지를 보여준다. 이번 전시는 다큐멘터리 사진이 단순한 순간의 기록을 넘어 새로운 의미를 부여하는 예술로서의 가능성을 탐구하고 사진이 가진 예술적 가치를 재조명한다.&nbsp;</p><p>이 전시를 통해 관객들은 사진이 보여주는 기록과 표현의 경계에서 새로운 시각적 경험을 얻고, 사진이 가진 메시지와 예술적 힘을 느낄 수 있을 것이다.&nbsp;</p></div></div></div></div></div></div></div><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"></div></div></div></div></div></div><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><p>예술감독 &nbsp;&nbsp;양정아&nbsp;Artistic Director : Joanne Junga Yang</p></div></div></div></div></div></div></div> <p><br></p><p>[참여 작가 리스트]</p><p>마틴 파&nbsp;Martin Parr</p><p>다이도 모리야마&nbsp;Daido Moriyama</p><p>구와바라 시세이&nbsp;Shisei Kuwabara</p><p>이한구&nbsp;Han Koo Lee</p><p>프레데릭 벅스&nbsp;Frederik Buyckx</p><p>박하선&nbsp;Ha Seon Park</p><p>루시아 헤레로&nbsp;Lucia Herrero</p><div class="photo_img">디나 리토프스키&nbsp;Dina Litovsky</div><p>앤디 프리버그&nbsp;Andy Freeberg</p><p>팀 프랑코&nbsp;Tim franco</p><p>이성민&nbsp;Sung Min Lee</p><p>안세권&nbsp;Sekwon Ahn</p><p>나이젤 디킨슨&nbsp;Nigel Dickinson</p><p>조춘만&nbsp;Choon Man Jo</p><p>이삭&nbsp;Yisak Choi</p><p>마틴 푸즈롱&nbsp;Martine Fougeron</p> <br><p></p><p><br></p><p>[특별전]</p><p> </p><p>특별전은 유망한 사진가들을 발굴하고 그 가능성을 엿볼 수 있는&nbsp;“디스커버리(Discovery)”전과 자신만의 독특한 색채가 묻어나는&nbsp;“새로운 시선(New Perspective)”전으로 구성되어 관람객들에게 신선한 시각을 전달한다. 또, 각 지역마다 오랜 시간 묵묵히 자신만의 작업을 이뤄낸 작가의 무대를 마련하고 첫해는 충청권 작가를 소개한다.</p><p><br></p><p>특별전은 모두 9개의 전시장으로 스페이스 테미, 테미오래 6호, 화니갤러리, 설비원서점, 이공갤러리, 우연갤러리, 문화공간 주차, 아리아갤러리, 탄갤러리에서 진행된다.</p> <br><p></p><p><br></p><p>[전시장소]</p><p><br></p><p>1. 문화복합예술공간 대전예술가의 집; 대전광역시 중구 중앙로 32</p><p> 주제전-기록과 표현, 16인의 시각 </p><p><br></p><p>2. 대전 엑스포 시민광장 미디어 큐브동;&nbsp;&nbsp;대전광역시 서구 둔산대로 169 한밭수목원</p><p> 반려동물사진공모전, 동물작가 초대전 <br></p><p><br></p><p>3. 스페이스 테미; 대전광역시 중구 테미로 44번길 40</p><p> 난다-미지인의 초상 <br></p><p><br></p><p>4. 테미오래 6호; 대전광역시 중구 보문로 205번길 22</p><p> Koji Onaka-Slow Boat <br></p><p><br></p><p>5. 화니갤러리; 대전광역시 중구 대흥로 71번길 27</p><p><br></p><p>6. 설비원서점; 대전광역시 중구 대흥로 121번길 30-5</p><p> 충청 향토작가초대전-조임환 신영팔 김운기 <br></p><p><br></p><p>7. 이공갤러리;&nbsp;대전광역시 중구 대흥로139번길 36</p><p> 디스커버리전-강민아 이동욱 이호준 정은진</p><p>&nbsp; <br></p><div class="photo_img"><div class="photo_img"><div class="photo_img"></div></div></div><div class="photo_img">8. 우연갤러리;&nbsp;대전광역시 중구 대종로 467</div><div class="photo_img"> 아카데미전-텐 보이스 <br></div><div class="photo_img"><br></div><p></p><p></p><div class="photo_img"><div class="photo_img"><div class="photo_img"></div></div></div><div class="photo_img">9. 문화공간 주차;&nbsp;대전광역시 중구 대흥로157번길 40-12</div><div class="photo_img"> 신진호-미얀마 <br></div><div class="photo_img"><br></div><p></p><p>10. 아리아 갤러리;&nbsp;대전광역시 중구 중앙로170번길 48</p><p> 해외협력전-Lensculture <br></p><p><br></p><p>11. 탄갤러리;&nbsp;대전광역시 서구 문정로 148 굿앤월드빌딩</p><p> 환경·생태전-정봉채 <br></p><p><br></p><p><br></p><p>[일시]</p><p>2024.11.13 - 24</p><p><br></p><p>[링크]</p><p> 대전국제사진축제 <br></p><p></p><div class="photo_img"><br></div><p></p></div></div></div></div></div></div></div>', '2024-10-24 09:35:37');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('b7db5dde-6e73-43a0-8748-fbdf10859d48', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전동구] 우암의 길', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/019d1be2-88a6-4409-9fcf-8d47bc69a39d" data-image-index="0" alt="mosaNFoAVv.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">가 볼만한 행사를 추가적으로 찾아서 좀 늦었지만 공지 드립니다&#39;-&#39;&nbsp;</div>', '2024-10-20 23:33:21');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('24f71429-ecee-4227-adad-8addb3c87b27', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 세 번째 북토크  <김진향 작가>와 함께하는 "인간행복"', '<div class="photo_img">이번주 토요일이라 며칠 안남아서 관심있으시면 빠르게 신청해주세요~</div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/f22a9eb4-58e0-4469-9cd6-0c2cc0a6fe96" data-image-index="0" alt="mosaVuFDG4.png" width="438"></div><br></div><div class="photo_img"><br></div><div class="photo_img">안녕하세요. 희망의책 대전본부 입니다. ^^ 몇 번의 비님이 오시더니 책 읽기 좋은 계절입니다.&nbsp;&nbsp;</div><div class="photo_img">이번에 준비한 세번째 북토크는&nbsp; &lt;김진향 작가&gt;와 함께하는 "인간행복" 입니다.</div><div class="photo_img">&nbsp;</div><div class="photo_img">[북토크 일정]</div><div class="photo_img">- 일시 : 2024년 10월 12일(토) 17시,&nbsp;</div><div class="photo_img">- 장소 : 지식산업센터 602호, &lt;대동역 1번 출구&gt;&nbsp;</div><div class="photo_img">- 링크 : bit.ly/인간행복</div><div class="photo_img"><br></div><div class="photo_img">&lt;책소개&gt;</div><div class="photo_img">“행복에는 분명한 답이 있다. 행복에는 명확한 본질이 있다.”</div><div class="photo_img">행복의 본질-근원에 대한 보편적 규정은 가능하다.</div><div class="photo_img">사람들이 추구하는 다양한 행복의 상태에 공통된 근본 성질의 총체가 존재한다.</div><div class="photo_img">그것이 바로 행복의 본질이다.</div><div class="photo_img">수많은 행복의 공통분모인 행복의 본질을 찾으면 행복은 규명된다.</div><div class="photo_img">절대에 가까운 진리로서 행복의 본질을 규명하고 나누고자 쓴 책이다.</div><div class="photo_img">행복의 본질을 제대로 몰랐기 때문에 우리는 온전히 행복할 수 없었다.</div><div class="photo_img">행복의 본질은 인간의 본성인 자기 존엄 추구의 본성, 자존이다.</div><div class="photo_img">결국 행복의 근원은 인간의 존엄성이다.</div><div class="photo_img">행복의 본질은 모든 인간이 평생에 걸쳐 매 순간 체현하고자 하는 인간의 궁극적 본성인 인간존엄성 안에 있었다.</div><div class="photo_img">행복은 인간이면 누구나 가진 기본권인 천부인권의 인간존엄을 실현하는 것이다.</div><div class="photo_img">행복의 근원은 인간의 존엄성이며 행복의 본질은 인간의 자기 존엄 추구의 본성, 자기 존엄 실현의 본성, 자존의 본성, 자존(自尊)이다.</div><div class="photo_img">인간존엄이 천부인권이듯 인간행복도 천부인권이다.</div><div class="photo_img">인간행복의 천부인권을 선언하자.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">&lt;작가소개&gt;</div><div class="photo_img">대구 달성 하빈… 가야산-낙동강-저녁노을-하목정… 작가의 고향을 상징하는 단어들이다.</div><div class="photo_img">생명 움터오는 연초록 봄날과 하늘빛 고운 청명한 가을, 사랑 깊어 가는 겨울을 좋아한다.&nbsp;</div><div class="photo_img">노을 물드는 저녁하늘, 바람 부는 산과 들, 햇살 부서지는 강과 바다를 시리게 좋아한다.&nbsp;</div><div class="photo_img">그 자연을 느끼며 걷기를 좋아한다. 시와 노래를 좋아한다.</div><div class="photo_img">사람을 좋아하고 공동체를 사랑한다. 인간의 존엄, 사랑과 행복을 최고의 가치로 추구하며 실천하는 삶을 살고자 한다.&nbsp;</div><div class="photo_img">그런 삶 속에서 ‘항상 바른 마음, 진실되고 성실하게 사람사랑 조국사랑’이 시나브로 좌우명이 되었다.&nbsp;</div><div class="photo_img">인간답게 살고 싶은 인간다움이나 사람이 사람답게 사는 사람 사는 세상 모두 인간의 존엄을 실현하려는 인간 본성으로 보고 인간존엄 실현을 공동체의 궁극적 가치이자 목적으로 본다.</div><div class="photo_img">&nbsp;https://www.facebook.com/kjhym</div><div class="photo_img"><br></div><div class="photo_img">&lt;약력&gt;</div><div class="photo_img">정치학박사 / 한반도평화경제회의 의장</div><div class="photo_img">전)카이스트 미래전략대학원 연구교수</div><div class="photo_img">전)개성공단 지원재단 이사장</div><div class="photo_img">전)대통령비서실 비서관</div><div class="photo_img">전)NSC 사무처 행정관</div><div class="photo_img">행복책빵 대표</div>', '2024-10-10 10:24:34');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('17c58a1b-c70d-4d52-8fc4-00b1fc23cddc', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전광역시] 테마도서 북큐레이션 (명리학 바로보기)', '<div class="photo_img">동일한 내용으로 월평, 갈마, 둔산, 가수원 도서관 총 4 곳에서 진행 되는 걸로 확인 됩니다.</div><div class="photo_img">가까운 곳에 상기 네 곳의 도서관이 있다면 10월 중으로 언제든지 가도 되는 것 같으니 관심 있으신 분들은 찾아가 보세요~</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/c56bea7e-6a4b-4187-a432-855c1d7dfbbd" data-image-index="0" alt="mosa5YwHtQ.jpeg" width="438"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/e1461142-34d1-459b-b7b6-ae5803cb2b7e" data-image-index="1" alt="mosaZyDOci.jpeg" width="438"></div>', '2024-10-02 15:19:31');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('37808a67-30fe-4499-84ca-a34d8967bac8', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[송촌도서관] 10월 원화 전시 ''모두 다 음악''', '<p>​점차 밤이 길어가는 가을, 10월! 송촌도서관에서는 미란 작가님의 밝고 따스한 그림책 &#39;모두 다 음악&#39; 원화 전시를 준비했습니다.</p><p>​</p><p>많은 관심과 관람 부탁드립니다!</p><p>​</p><p>* 전시기간 : 10. 2.(수) ~ 10. 28.(월)</p><p>* 전시장소 : 송촌도서관 1층 로비</p><p><br></p><p><div class="photo_img"><img src="http://localhost:8080/api/attachments/e110d47c-5e61-4a85-8d98-9c91af482f82" data-image-index="0" alt="mosaH9w4NY.png" width="438"></div><br></p>', '2024-10-02 15:14:17');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('07a24f6f-aa25-4592-8d30-1f7260d26e45', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[구암도서관] 유성 독서대전 (현장접수) 정유정 작가와의 만남', '<div class="photo_img">행사기간&nbsp;: 2024-10-13 ~ 2024-10-13장소&nbsp;: 유림공원 동편강사명&nbsp;: 정유정 작가연락처&nbsp;: 042-611-6631</div><div class="photo_img"><p>2024&nbsp;대전유성구 한국지역도서전&nbsp;&amp;&nbsp;유성 독서대전 행사 프로그램으로 아래 강연을 진행합니다!!<br>&nbsp;</p><p>-&nbsp;일&nbsp; &nbsp; 시: 10. 13.(일) 13:00 ~ 14:30&nbsp;현장접수</p><p>-&nbsp;장&nbsp; &nbsp; 소: 유림공원 동편 잔디광장</p><p>-&nbsp;강연자: 정유정 작가 /&nbsp;「7년의 밤」,&nbsp;「28」,&nbsp;「영원한 천국」 등</p><p>-&nbsp;내&nbsp; &nbsp; 용: 정유정 작가에게 듣는 신작&nbsp;&nbsp;「영원한 천국」 이야기<br><br></p></div>', '2024-10-02 15:12:43');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('01b7e44b-0af2-4e46-a0e3-316fa2c6b609', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[한밭도서관] 10, 11월 행사안내', '<div class="photo_img">간략하게 요약한 내용입니다.</div><div class="photo_img">관심 있는 강연 있으시면 찾아보시거나 궁금한 부분 있으면 톡방에 자유롭게 물어보세요~ &#39;-&#39;</div><div class="photo_img"><br></div><div class="photo_img">- 길 위의 인문학 [12회차]<br></div><div class="photo_img">주&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 제 : 대전 시민이 담긴 영화 &#39;하루&#39;</div><div class="photo_img">강&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 사 : 배기원 (영화감독)</div> 행사기간&nbsp;: 2024-10-08 ~ 2024-10-08<div class="photo_img">장&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 소&nbsp;: 한밭도서관 다목적홀(지하1층)&nbsp;&nbsp; </div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img">- 대전지역 공공도서관 작가초청 릴레이 강연회<div class="photo_img"><div class="photo_img"><div class="photo_img"></div></div><div class="photo_img"></div></div>주&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 제 :&nbsp;바로크 미술과 몰입형 전시의 탄생</div><div class="photo_img">강&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 사 : 양정무 (교수)</div><div class="photo_img">행사기간&nbsp;: 2024-11-14 ~ 2024-11-14</div><div class="photo_img">장&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 소&nbsp;: 한밭도서관 다목적홀(지하1층)&nbsp;&nbsp; &nbsp;&nbsp;</div><div class="photo_img"><br></div> </div><div class="photo_img">- 인문학에게 길을 묻다 [4차시]<br></div><div class="photo_img"><div class="photo_img"> <div class="photo_img">주&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;제 : 금시조 바다를 가르다: 시선과 시성<br>강&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;사 : 김성곤(교수)</div>행사기간&nbsp;: 2024-10-17 ~ 2024-10-17</div><div class="photo_img">장&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 소&nbsp;: 한밭도서관 다목적홀(지하1층)&nbsp;&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img">- 인문학에게 길을 묻다 [5차시]<div class="photo_img"><div class="photo_img"><div class="photo_img"></div></div><div class="photo_img"></div></div> <div class="photo_img">주&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 제 : 모던 빠리: 예술의 흐름을 바꾼 열두 개의 전시<br>강&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 사 : 박재연 (교수)</div></div><div class="photo_img">행사기간&nbsp;: 2024-11-21 ~ 2024-11-21</div><div class="photo_img">장&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 소&nbsp;: 한밭도서관 다목적홀(지하1층)&nbsp;&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">자세한 내용은 아래 링크 참조해주세요~</div><div class="photo_img"> 대전광역시 한밭도서관 (daejeon.go.kr) <br></div><div class="photo_img">https://www.daejeon.go.kr/hanbatlibrary/cultureEventList.do?menuSeq=6234<br></div></div></div>', '2024-10-02 15:11:52');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('d0c8640a-2854-43f6-8e39-026aa3ac4665', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전광역시] 대전광역시 10월 전체 공연 및 전시 일정', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/bdb38f2d-ba7b-4f62-9a0b-b1f9416d5b0c" data-image-index="0" alt="mosaxnoc1F.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">10월 일정나왔습니다~</div><div class="photo_img"><br></div><div class="photo_img">주요하게는&nbsp;</div><div class="photo_img">10.15. (화), 17. (목) 22. (화), 24. (목) 19:30에 총 4번의 화목한 문화산책 (대전 월평초등학교 강당)과<br></div><div class="photo_img"><br></div><div class="photo_img">10. 25. (금) 19:30 R.슈트라우스 장미의 기사 모음곡&nbsp; (대전예술의전당 아트홀)두 개가 있네요 ㅎㅎ</div><div class="photo_img"><br></div><div class="photo_img">관심있으신 분들 살펴보시구 잘 다녀오세요 ~</div>', '2024-10-02 14:57:59');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('d80be00d-23ca-44fa-b327-59938f7bf58e', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대덕구] 2024 독서문화축제', '<div class="photo_img"> <div class="photo_img"><img src="http://localhost:8080/api/attachments/81b6bec9-114c-47f6-beda-fc77a09fd883" data-image-index="3" alt="mosainEYch.jpeg" width="438"></div><br></div><div class="photo_img"><br></div><div class="photo_img"> <img src="http://localhost:8080/api/attachments/1b5eb598-68be-4ef5-9e76-ae50db34dbc1" data-image-index="1" alt="mosaOrIKXP.jpeg" width="438"> <br></div><div class="photo_img">이건 아쉽지만 저희가 못하겠네요 ㅋ. ㅋ</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/76e705c1-38d3-40bf-98c7-436520a2b93f" data-image-index="0" alt="mosa0OgBBa.jpeg" width="438"></div><div class="photo_img">체험거리나 즐길거리는 저희가 좀 해 볼 만한게 있을지도 모르겠네요</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/09fb4391-0f15-4f71-a8fd-7bc8e6097e4b" data-image-index="2" alt="mosaLMArc2.jpeg" width="438"></div><div class="photo_img">오후에 공연이 꽉 차 있네요</div><div class="photo_img">골라서 시간대 맞춰서 가도 좋을 것 같네요</div>', '2024-09-10 09:20:42');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('a5d0c139-4e86-4dbc-9c92-72f6c99fa6f8', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[월평도서관] 2024 서구 책 축제', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/58fcedce-a37f-43e9-baa8-a8bc8a4c611a" data-image-index="0" alt="mosapXHzO3.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/81c1363f-2169-4e2f-8c78-d7998f8fa9e8" data-image-index="1" alt="mosaxe9Mue.png" width="438"></div><div class="photo_img"><br></div><div class="photo_img">읽어보니 기념품은 선착순 조건이 있네요.</div><div class="photo_img">특별행사는 사전신청 해야만 볼 수 있는 것도 있으니, 참여하실 분은 꼭 확인해주세요~</div><div class="photo_img"><br></div><div class="photo_img">* 이번 달인 9월 정모 때 서구 책 축제 사전행사를 참여해볼까 합니다. 많은 관심 부탁드려요 ~. ~</div>', '2024-09-10 09:17:18');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('b0050338-776a-46d7-961a-42b8d148c8ba', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전광역시] 대전광역시 9월 전체 공연 및 전시 일정', '<div class="photo_img">9월 전시 및 공연 일정입니당 ~</div><div class="photo_img"><br></div><div class="photo_img">관심 있으신 분 얘기해주세요 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/41850811-2c1f-4d09-884f-00925d69bf53" data-image-index="0" alt="mosatigdvw.jpeg" width="438"></div>', '2024-09-03 15:12:51');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('b86b6d83-4bfc-4abf-966e-cffad8458e8c', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전시립예술단] 2024 보문산 숲속의 열린음악회', '<div class="photo_img">공지 자체는 조금 늦은 감이 있는데 예약제가 아니라 무료라서 공유 드립니다.</div><div class="photo_img">관심 있으신 분들은 한 번 찾아가 보셔요 ㅎㅎ</div><div class="photo_img"><br></div><div class="photo_img"> <img src="http://localhost:8080/api/attachments/cc43e06a-483a-4a91-9d51-489be08f2a83" data-image-index="1" alt="mosaEOC82z.png" width="438"> <br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/1ee31b6c-b08a-4522-9597-defbe9c72fcb" data-image-index="0" alt="mosaLhlupS.png" width="438"></div><div class="photo_img"><br></div>', '2024-08-29 14:11:29');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('bf083cda-9ebd-414c-ae76-b81129679504', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 2024 우리대전 같은책 읽기 <우리의활보는사치가아니야>', '<div class="photo_img">이번에도 희망의책 대전본부 북토크 행사 올라와서 공유드립니다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">본 문 내용 아래는 간단하게 보시라고 올려놓은 공고 본문이고,</div><div class="photo_img">&gt;&gt; 홈페이지 링크 들어가서 꼭 확인해주세요 ~</div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img">- 희망의책 대전본부 최신공지사항 -</div><div class="photo_img"></div>http://www.djbook.or.kr <br></div><div class="photo_img"> </div><div class="photo_img"><img src="http://localhost:8080/api/attachments/492fffe6-b03c-415b-9cd1-6216cbf97350" data-image-index="0" alt="mosaKayoUy.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">2008년부터 시작된 사. 희망의책 대전본부의 [우리 대전 같은 책읽기] 사업이 올해로 제 17회를 맞이하여&nbsp;</div><div class="photo_img">2024년 8월 24일(토) 2시, 한밭도서관에서 올해의 책 &lt;우리의 활보는 사치가 아니야&gt; 선포식과 저자와 함께하는 북토크를 진행합니다^^*</div><div class="photo_img">링크를 통해 사전신청을 받고 있으며 참석하신 모든 분들께는 올해의 책을 배포합니다!!</div><div class="photo_img">특별히 [굴러라 구르님]으로 유투브채널을 운영하고 계신 작가님의 사인회도 함께 기획하고 있으니 많은 관심과 참여부탁드립니다. ^^*</div><div class="photo_img"><br></div><div class="photo_img">- 일시 : 2024년 8월 24일(토) 2시,&nbsp;</div><div class="photo_img">- 장소 : 한밭도서관 다목적홀</div><div class="photo_img">- 신청 : https://bit.ly/제17회우리대전같은책읽기</div><div class="photo_img"><br></div><div class="photo_img">*2024년 올해의 책&lt;우리의활보는사치가아니야&gt;은 휠체어를 탄 여자가 인터뷰한 휠체어 탄 여자들이라는 부제처럼 10대부터 60대에까지 휠체어를 탄 롤모델을 만나는 인터뷰집입니다!</div>', '2024-08-19 10:00:22');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('0af36cf9-5ea1-4031-8168-b0721a6faee0', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전광역시] 대전광역시 8월 전체 공연 및 전시 일정', '대전시 전체 공연 및 전시 일정 달력 공유 드립니다~<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/a2d4026a-a68d-4f53-8ab9-a8d33291dfe0" data-image-index="0" alt="mosaP70eh3.jpeg" width="438"></div><br></div>', '2024-08-04 23:25:07');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('286f1c00-bd35-41ac-b489-803f1483abb4', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 	2024 책읽는 사업, "이선배 저자"와 함께하는 북토크', '<br>2024 책읽는 사업, "이선배 저자"와 함께하는 [게임체인저:기본소득] 북토크 <div class="photo_img"><br></div><div class="photo_img">희망의책 대전본부에서 북토크를 진행한다고 합니다.</div><div class="photo_img"><br></div><div class="photo_img">아래 사진과 글은 희망의책 대전본부 공지글 복사본 입니다.</div><div class="photo_img">혹시나 관심있으신 분들은 제일 아래 링크를 따라 들어가서 원문을 꼭 확인해주세요~<br><div class="photo_img"><img src="http://localhost:8080/api/attachments/591d5b35-b027-4111-807d-7f5de1b04aea" data-image-index="0" alt="mosa9xB6GB.png" width="438"></div><div class="photo_img"><div class="photo_img">안녕하세요. ^^</div><div class="photo_img"><br></div><div class="photo_img">희망의책대전본부 입니다.&nbsp; 벌써 2024년도 중반을 넘어섰습니다.&nbsp;</div><div class="photo_img">그동안 대전지역의 독서동아리들의 활성화를 위한, 도서지원, 음료지원을 시작으로 올해 한권책을 선정하는 선정위원회를 거쳐 선포식을 앞두고 있습니다.</div><div class="photo_img">올해에는 어떤 책으로 10번의 북토크를 시민분들과 나눌까 기대하면서 기다려온 2024년 책읽는 사업!! 드디어 첫번째 북토크 입니다!!</div><div class="photo_img">[게임체인저 : 기본소득]&nbsp; 초등학생 3학년이상이라면 쉽게 이해하도록 풀어놓은 책이지만 모든 연령에게 꼭 필요한 책입니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">[작가와 함께하는 "게임체인저"기본소득" 북토크 일정&amp;신청]</div><div class="photo_img">&nbsp;-&nbsp; 2024년 8얼 11일 일요일 오후 4시, 전민동 강스튜디오(유성구 전민로 6번길 81)</div><div class="photo_img">&nbsp;-&nbsp; 신청: https://bit.ly/게임체인저_기본소득&nbsp;</div><div class="photo_img">&nbsp;-&nbsp; 참여하신 모든 분들께 책을 선물로 드립니다. ^^*</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">[알라딘 저자소개]</div><div class="photo_img">30년동안 대전에서 독서논술지도로 유명하신 이선배 작가님께서 출간하신 4번째 책 [게임체인저 : 기본소득]입니다.</div><div class="photo_img">작가는 서울교육대학교를 졸업하고&nbsp; 기본소득한국네트워크 회원으로 기후위기, 일자리 문제, 성차별, 자산과 소득 불평등 등 현 사회가 직면한 문제에 대해 기본소득이 해결의 실마리가 될 수 있음을 깨닫고, 책 쓰기 작업 등을 통해 기본소득 캠페인에 동참하고 있다. 독서교육연구회, 희망의책대전본부에서 좋은 독서생태계 구축을 위해 꾸준히 노력 중이다. 전국의 초중등 학생들과 온라인 화상 수업을 통해 매주 좋은 책을 함께 읽고, 토의하고, 글 쓰는 ‘이선배독서교실’이 생업이다. 지은 책으로는 『그건 내 건데』 『대갈장군이어도 좋아!』 『재명아! 기본소득이 뭐야?』가 있다.</div><div class="photo_img"><br></div><div class="photo_img">[알라딘 책소개]</div><div class="photo_img">누구나 조건 없이 누려야 할 권리이자 대가 없이 주어지는 현금인 기본소득! 현실성이 없다는 둥 이상적이라는 둥 해묵은 논쟁은 집어치우고, 진짜 우리 시대 판을 바꾸는 게임 체인저(game changer)로 기본소득을 소환한다!</div><div class="photo_img">기후위기를 걱정하는 강기후, 로봇과 AI로 인한 실업을 두려워하는 노본회퍼, 자산과 소득 불평등 현실을 부당하게 여기는 지소유, 가부장제로 벌어진 가정 폭력과 성차별에 분노하는 극득남 그리고 기본소득 옹호자 공유부! 다섯 아이가 가상 게임 공간에 모였다. 갖가지 사회 문제를 해결하고 싶었지만 현실적인 문제에 부딪혀 이도 저도 선택할 수 없던 아이들에게 가상 공간에서 만난 토머스 페인 할아버지는 기본소득을 제시한다. 각종 갈등과 방해를 피해 우리가 바라는 더 나은 세상을 만들 수 있을까?</div><div class="photo_img">『그건 내 건데』로 기본소득의 철학과 방법을 알려 온 이선배 작가가 이번엔 어린이 문학으로 재미나고 흥미진진하게 기본소득이 만들 수 있는 세상을 그려 냈다. 다섯 아이들과 토머스 페인이 어떻게 기본소득을 활용해 문제를 해결해 나가는지 따라가다 보면 순식간에 독자들도 기본소득 특공대가 되어 있으리라! 여기에 맹하나 그림 작가의 솜씨가 더해져 독자의 상상력을 한층 자극한다.</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img">- 희망의책 대전본부 최신공지사항 -</div><div class="photo_img"> </div> http://www.djbook.or.kr<div class="photo_img"><br></div></div></div>', '2024-08-04 23:18:05');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('18ec38cf-1ecf-4c9e-9008-11a141c9c6dd', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전 시립예술단] 대전 영시축제 전시 및 공연', '<div class="photo_img">대전 시립예술단이 24년도 영시축제 공연 및 전시 일정을 따로 가독성 높게 공지해서</div><div class="photo_img">공유 드립니다~ 관심 있으신 분들은 한 번 찾아 보세요~ &#39;-&#39;</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/923fe8f2-03ff-4884-a0e7-365e2a4aa8c2" data-image-index="0" alt="mosatlZevb.jpeg" width="438"></div>', '2024-08-04 23:13:03');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('15029297-108a-4f28-a1ed-f9da61eaf34f', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전시립무용단] 문화예술강좌 신청', '<div class="photo_img">대전 시립 무용단에서 우리나라 부채춤 강좌를 연다고 합니다.</div><div class="photo_img">관심 있으신 분들은 오픈 카톡 일정에 링크 걸어 놨으니 찾아 가보셔요~ ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/af64c29c-9985-4efa-a36d-6f38feeec759" data-image-index="0" alt="mosaicwGft.jpeg" width="438"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/01090a08-74af-4f07-af0f-9c7340331b5b" data-image-index="1" alt="mosapdDhVG.jpeg" width="438"></div>', '2024-07-01 16:19:07');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('789e1f4c-e3ca-4257-b3a7-072981a72207', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[한밭도서관] 토요 문화광장', '한밭도서관에서 운영하는 이번 7월 행사는 마술 공연이랑 영화가 있네요<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/58da4ae9-7645-440a-860c-a31faf425d6d" data-image-index="0" alt="mosazQmTYt.jpeg" width="438"></div><br></div>', '2024-07-01 16:15:20');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('140de008-6685-44bc-bc39-9b5324f078f6', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전시립연정국악단] 토요국악 상설공연', '<div class="photo_img">대전시립연정국악단에서 7월 마지막 주 토요일 오후 2시에 공연이 있다고 하네요~</div><div class="photo_img"><img src="http://localhost:8080/api/attachments/c0a79e85-9292-4ab9-acab-7f2a890d2ed3" data-image-index="0" alt="mosaTF3LJA.jpeg" width="438"></div>', '2024-07-01 16:13:58');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('824697a9-a808-4997-909e-a9304df63ef6', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전 공연전시] 세빌리아의 이발사', '<div class="photo_img">대전 예술의 전당에서 오페라 공연이 있다고 합니다~</div><div class="photo_img"><img src="http://localhost:8080/api/attachments/36eefac6-5287-4deb-9f07-81bb2d6f716b" data-image-index="0" alt="mosa8xG5Xf.jpeg" width="438"></div>', '2024-07-01 16:12:29');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('5863c2e4-9813-4e18-bf7c-c03ea59df805', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전 축제] 행사 예정 안내 포스터', '<div class="photo_img"></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/b9febe38-c048-40ad-9b4e-3e7fc06e18a0" data-image-index="3" alt="mosa78xoDt.jpeg" width="438"></div><img src="http://localhost:8080/api/attachments/b99d9fea-7948-4c28-b2a5-604b50fb8299" data-image-index="0" alt="mosaVvX4Bb.jpeg" width="438"></div><div class="photo_img"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/78569a02-4006-412a-bd96-29df4b8dfcd1" data-image-index="1" alt="mosaPTWWLJ.jpeg" width="438"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/e59921b6-7942-453c-b474-8be7ffbada5c" data-image-index="2" alt="mosaR8cu0R.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">시간 순서대로 나열해 놓았습니다~</div>', '2024-06-11 17:02:49');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('e50cb33e-b001-4973-b162-4135e5e0277b', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 24년도 독서동아리 지원사업 결과', '<div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/2005ad0a-2e07-4106-bdb2-39864be80774" data-image-index="0" alt="mosav5OB1n.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img"><br></div>지원 사업 선정되었습니다!</div><div class="photo_img"><br></div><div class="photo_img">아래 글은 공지글 원문 입니다. &#39;-&#39;</div><div class="photo_img">---------------------------------------------------------------------------------------------</div><div class="photo_img"><br></div><div class="photo_img">2024년 독서동아리 지원 사업에 뜨거운 관심을 보여주셔서 고맙습니다.</div><div class="photo_img">전체 68개 동아리에서 836만 5300원어치 도서지원을 신청했습니다. 또 28개 동아리에서 88만 원어치 공간지원을 위한 음료비를 신청했습니다.</div><div class="photo_img"><br></div><div class="photo_img">2024년 대전시로부터 희망의책이 독서동아리 지원으로 책정 받은 예산은 630만 원입니다. 예산 대비 146.7% 신청으로 불가피하게 다음 원칙에 따라 지원 동아리를 결정했습니다.</div><div class="photo_img">1. 희망의책에 등록한 신규 동아리를 응원 차원에서 우선 도서를 지원한다.</div><div class="photo_img">2. 기존 동아리 중 희망의책 각종 사업에 적극 참여한 동아리를 도서를 지원한다. (우리같은책읽기, 가을책잔치, 북큐레이션 등 사업에 참여 동아리, 희망의책 정회원 참여 동아리)</div><div class="photo_img">3. 1,2항목에 해당하지 않은 동아리 중 공간 지원 (음료비) 동아리를 지원한다.</div><div class="photo_img">4. 1,2,3항목에 해당하지 않은 희망의 책 미등록 신규 동아리 및 기존 동아리 중 2021~23년도 희망의책으로부터 지원을 받은 동아리는 지원 도서 중 일부 도서를 지원한다.</div><div class="photo_img"><br></div><div class="photo_img">** 일부 동아리를 지원에서 탈락시키고, 소수 동아리라도 신청한 도서 모두를 지원하는 방안도 고민했으나 조금씩이라도 모든 동아리에게 지원하기로 결정했습니다.&nbsp;</div><div class="photo_img">대전시 책정 예산 부족으로 인해 불가피한 선택이니 이해 부탁드립니다.&nbsp;</div><div class="photo_img">대전시 독서동아리 지원 예산이 확대되어서 대전시 독서문화 확산에 앞장서는 독서동아리 회원들에게 책 한 권, 음료 한 잔 넉넉하게 지원할 수 있기를 바랍니다.</div><div class="photo_img"><br></div><div class="photo_img">다음은 지원받는 동아리 명단입니다.</div><div class="photo_img"><br></div><div class="photo_img">- 도서지원 동아리 57개 동아리 594만 5200원</div><div class="photo_img">2030월급쟁이독서모임 / COZY살롱 / MABS북클럽 / STEADY / 가득이북독서모임 / 경제적자유를위한독서모임 / 고전의향기 /공감 / 관저2동복지분과팀 / 관저동독서클럽 /</div><div class="photo_img">글꽃살롱 / 꿈독 /넷제로해유 / 노은인문학모임 / 녹색평론읽기모임 / 대전포스트잇 / 대전동네책방 / 대전마을작은도서관협의회사서분과 / 대전월요독서모임 /</div><div class="photo_img">덕산넵코어스독서동호회 / 동구북클럽 / 또바기 독서 러닝크루 / 라까니언 / 레아북클럽 / 마인드넷 / 미술서가 / 민들레읽기모임 / 방구석살롱 / 북톡스 /</div><div class="photo_img">사회적참사대전기억단(대전청년회) / 수북수북 / 알로발도르프! /알음알음 / 어,울림 / 어린이책읽는어른 / 우리들의대나무숲 / 이아독 / 작은꽃다지 / 조화로운만남 /</div><div class="photo_img">좋은이웃 / 지혜의숲 / 책읽는민단단 / 책마실 / 책봄 / 책사랑향기 / 책수다 / 책읽는방 / 책읽는어른모임 / 책잇는맘 / 책책이 / 친구랑교사회 / 토닥토닥그림책 / 페퍼민트 /</div><div class="photo_img">한 장두장 / 해시민살롱in충청 / 행복한 그림책모임 / 홀가분</div><div class="photo_img"><br></div><div class="photo_img">- 음료지원 동아리 11개 동아리 35만 5000원</div><div class="photo_img">내일은맑음 / 사협마을아줌마책모임 / 생각더하기 / 소설산책 / 오독오독 / 오리건의여행 / 유성책바라기 / 이음 / 젤리에서젤리로/ 책드림 / 책한그루(독서토론)</div><div class="photo_img">&nbsp;</div><div class="photo_img">자세한 내용은 6월 10일 오전중으로 개별 동아리별로 따로 연락드리겠습니다. ^^&nbsp;&nbsp;</div><div class="photo_img">앞으로도 대전시민들과 함께 건강한 독서생태계를 만드는 일에 독서동아리 회원 여러분들이 앞장서주시길 부탁드립니다. 희망의책도 여러분과 함께 하겠습니다. 고맙습니다.</div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img">---------------------------------------------------------------------------------------------</div><div class="photo_img"><br> </div><br></div><div class="photo_img">다음에도 이러한 사업이 있으면 참여할 예정이니 관심 있으신 분은&nbsp; 많은 참여 부탁 드립니다 &#39;-&#39;</div>', '2024-06-07 15:01:53');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('75c03e74-eb6b-47c5-ae4d-5cac5dfb1b67', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[일류경제도시 대전] 24년도 화목한 문화산책', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/04e172c6-748d-40f8-97f8-0dbc829f3011" data-image-index="0" alt="mosap5hN23.png" width="438"><div class="photo_img"><img src="http://localhost:8080/api/attachments/0fb48a96-02e5-47a9-831a-440da53e7866" data-image-index="1" alt="mosav0blSn.png" width="438"></div><div class="photo_img"><br></div><div class="photo_img">문화공연 공유드립니다~</div><div class="photo_img">입장료는 따로 없다고 하는 것 같네요 ㅎ. ㅎ</div></div>', '2024-06-07 12:31:50');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('0e0f5ee1-ea15-4a7a-8a89-8395f8d0456c', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[대전광역시체육회] 24년도 대전 달빛 걷기대회', '<p>독서 행사는 아니지만,</p><p>여유 있으신 분 있으면 오후에 만나서 책도 읽고 간단히 저녁 먹고 행사 참여하면서</p><p>즐거운 주말이 되지 않을까 싶어서 공유드립니다 &#39;-&#39;</p><p><br></p><p><img src="http://localhost:8080/api/attachments/8b9aac1d-a291-442a-8e0e-16a4b230e540" data-image-index="0" alt="mosaCOPRys.png" width="438"><br></p><p><br></p><p> </p><p>제13회 월화수목 대전달빛걷기대회 대회개요</p><p><br></p><p>○ 일시 : 2024년 6월 22일(토) 18:00 ~<br><br>○&nbsp;장소 : 대전엑스포시민광장<br><br>○&nbsp;대상 : 대한민국 남.녀.노.소 누구나 신청 가능<br>&nbsp; &nbsp; &nbsp; &nbsp; (단, 만 14세 이하는 보호자 동반시에만 신청 가능)<br><br>○&nbsp;코스 및 참가비 :&nbsp;달빛코스 7Km&nbsp;참가비 무료<br><br>○&nbsp;참가신청<br>&nbsp;&nbsp;- 중도일보 홈페이지&nbsp;www.joongdo.co.kr&nbsp;팝업 또는 우측 상단 배너<br>&nbsp;&nbsp;- 이메일 : jbplus1@naver.com<br>&nbsp;&nbsp;- 전화 : 042 - 220 - 1041~2<br>&nbsp;&nbsp;- 사전접수 : ~ 6월 14일(금) 접수 마감 (선착순 1,000명)<br>&nbsp;&nbsp; &nbsp;현장접수 : 6월 22일(토) 18:00 ~ 19:00 (선착순 2,000명)<br><br>○&nbsp;주최 : (주)중도일보사, 대전광역시체육회</p> <br><p></p>', '2024-06-03 09:31:26');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('3e26e0b3-8f4e-4f34-aa91-22dfe0fc1e01', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[전민복합문화센터] 제스모나이트 친환경 트레이 만들기 행사 안내', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/83e9b3d9-abe1-4e5f-84dd-d6285d934ccc" data-image-index="0" alt="mosahoeDEV.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">행사 일정 공유해주셔서 공지 드립니다~~</div><div class="photo_img"><br></div><div class="photo_img">참여 하고싶으신 분들은 사진 꼼꼼히 읽고 실수 없이 신청 하셔요~</div>', '2024-05-29 14:19:25');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('72082827-836b-4741-be5a-a040bf3e2e1b', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 독서모임 신청 결과', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/52d9b3ce-8fe8-46b1-81da-335877cae173" data-image-index="0" alt="mosajk3JaI.png" width="438"></div><div class="photo_img">이번주 월요일에 신청했는데 등록되었네요 ㅎ. ㅎ</div>', '2024-05-22 14:19:01');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('dea264a3-e47b-4385-b145-9235b126dbed', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[희망의책 대전본부] 24년도 독서동아리 지원사업 안내', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/c5b4bf6d-1456-490f-bcde-38df54c629ea" data-image-index="0" alt="mosa81VvZy.png" width="438"></div><div class="photo_img"><br></div><div class="photo_img">대전광역시에서 독서 동아리 활성화&nbsp; 및 네트워크 형성을 돕고자 지원 사업을 하고 있다고 합니다.</div><div class="photo_img">저희 모임도 지원사업 공모에 참여 해볼까 합니다. ^^ 신청하고 통과된다면 알려드릴게요 ~</div>', '2024-05-20 13:17:00');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('5eafb97d-615d-4e2e-963d-6329a6b1d31a', 0, true, false, 'HTML', '70cdb7f0-17f9-45e7-a872-914a968c09b6', 'yasha_bread', '[가오도서관] 24년도 04~06월 대전 동구청 야외 행사 안내', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/4fde7f5c-02b6-40fd-96e3-c97bf03e7a51" data-image-index="0" alt="mosaFkGcFb.jpeg" width="438"></div><div class="photo_img"><br></div><div class="photo_img">가오 도서관에서 야외 도서관 행사가 있다고 하네요 ㅎ. ㅎ</div><div class="photo_img">4월부터 6월까지 한 달에 한 번 씩 행사가 있으니 시간 맞으신 분들은 가보세요~</div>', '2024-05-20 13:13:35');
