INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('935ed541-f4f5-49e6-9bd2-4b4bb4ff51cc', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 10/15 자유독서모임 후기', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/f87d7bfa-6bd5-459d-a3d7-cb23627c8f24" data-image-index="0" alt="mosa618bnO.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">이번 주는 오랜만에 둔산동 카페에서 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img">#둔산동 #나롬카페</div>', '2024-10-21 13:14:18');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('a980cd06-e833-4b7b-9ee2-14b1a4fae60a', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[희망의책대전본부] 3번째 북토크 인간행복-김진향', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/23807778-c2b9-4e51-b73d-484721c3426f" data-image-index="0" alt="mosaAeL2E0.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">정치학자이시자 작가이신 김진향 교수님의 책 인간행복.&nbsp;</div><div class="photo_img">인간이 언제 행복한가라는 근본적인 고민을 약 10년간 해오셨고 마침내 자신만의 결론에 도달하여 펴낸 책이라고 합니다.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img">모든 학문의 알파이자 오메가인 철학적 고찰을 통해서 바라보니 비로소 조금이나마 이해할 수 있지 않았나라고 하시며 철학의 부재에 대한 &#39;분노&#39; 포인트 몇가지를 소개 해주셨습니다. ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img">#대전포스트잇</div><div class="photo_img">#대전광역시 #동구 #희망의책대전본부 #북토크 #지식산업센터&nbsp;</div><div class="photo_img">#인간행복 #작가김진향</div><div class="photo_img"><br></div>', '2024-10-14 09:17:09');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('d97c05a3-737d-4bcb-b9a0-645f448bcf2f', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 10/10 자유독서모임 후기', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/bb269196-e703-4f3e-a753-aec455c3b0da" data-image-index="0" alt="mosaeGFH9T.jpeg" width="257"></div><div class="photo_img">6명이었는데 읽느라 정신없어서 늦게 찍는 바람에</div><div class="photo_img">책 한 권이 모자라네요 ㅠㅠ..&nbsp;</div><div class="photo_img">담엔 꼭 모든 인원있을 때 찍어보겠습니다 ㅇ. ㅇ7</div><div class="photo_img"><br></div><div class="photo_img">#유성구#에이트</div>', '2024-10-10 21:44:53');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('9abe7e32-1330-49ea-95b7-0a0e360f42e8', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 10/4 자유독서모임 후기', '<div class="photo_img"><img src="http://localhost:8080/api/attachments/10af3619-d7ac-400e-92aa-ed6e4210a25b" data-image-index="0" alt="mosaJSe3lq.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">#중구#대흥동#윈터로스터즈</div>', '2024-10-10 21:42:03');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('4290af1f-a2a6-48e7-bf36-b5f6d0889469', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 9/24 자유독서모임 후기', '<div class="photo_img">오늘 자유독서는 평소보다 엄청 많은 분들이 참여해 주셨습니다.&nbsp;</div><div class="photo_img">슬슬 가을이라 그런지 다시 책 열풍이 부는 것 같네요 ㅎ. ㅎ</div><div class="photo_img">다들 담에 기회되면 다시 봬요~</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/6e636ee7-21cb-4334-84ed-4a6d2f7e0fed" data-image-index="0" alt="mosaqODEdH.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">#에어온 #서구 #시청역</div>', '2024-09-24 21:08:54');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('728cc999-5d67-44ad-a79a-f8ce89575918', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 09/21 정모 후기', '이번 달 정모는 앞뒤로 추석 연휴와 개천절의 황금 연휴 사이에&nbsp;끼어있어서 바빠지다보니&nbsp;한 주 빠른 9월 3째 주에 진행 하였습니다.<div class="photo_img"><br></div><div class="photo_img">9월에도 지난번부터 왔던 중구 에이블 카페에서 진행 했습니다&nbsp; ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img">이번에 비가 내려서 사람들이 많이 없을 줄 알았는데, 그럼에도&nbsp;불구하고 에이블스페이스에서 진행하는 시민 참여 행사도 하느라 사람들이 북적였습니다.</div><div class="photo_img"><br></div><div class="photo_img">정모에 처음 나오시는 분도 있으셔서 이번 달은 사진은 못 찍었지만 그동안 읽었던 "그 겨울의 일주일", "데미안" 등 다양한 책 이야기를 했습니다 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img"><div class="photo_img">#대전독서모임 #대전포스트잇 #문화동드로잉카페 #문화동카페에이블 #에이블스페이스<br></div></div></div></div></div><br> </div>', '2024-09-24 19:11:40');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('2ea44a7c-d547-486b-a8a9-df6e15f3888f', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 8/24 우리대전 같은책 읽기 <우리의활보는사치가아니야> 북토크 참여 후기', '<div class="photo_img">이번 주는 우리대전 같은 책 읽기 !</div><div class="photo_img">우리의 활보는 사치가 아니야 라는 책의 저자 구르님의 북토크를 다녀왔습니다.</div><div class="photo_img">이번에도 역시 희망의책 대전본부에서 진행하는 독서 행사였는데요,</div><div class="photo_img">그래도 두 번 째라 그런지 벌써 행사 주최하시는 분들의 얼굴이 익숙해 졌네요.</div><div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/e80f0cde-6230-43e9-9921-bb63461b34be" data-image-index="0" alt="mosaopx06O.jpeg" width="438"><br></div><div class="photo_img">구르님은 유튜버겸 작가라고 하시더라구요.</div><div class="photo_img">그래서 중간 쉬는 시간 잠시 짬내서 구독도 했습니다 ㅎ. ㅎ</div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/5aff9429-8608-4078-adc4-e7f57e8a8a37" data-image-index="2" alt="mosaMFDf7l.png" width="438"></div><br></div><div class="photo_img"> <br></div><div class="photo_img">역시 유튜버라 그런지 막힘없이 말씀 하시는 것 듣다 보니 시간 가는 줄 몰랐네요 &#39;-&#39;</div><div class="photo_img"><br><div class="photo_img"><img src="http://localhost:8080/api/attachments/d2fe95e4-9214-477a-86ae-425781e580d2" data-image-index="1" alt="mosaOKQgBj.jpeg" width="438"></div><div class="photo_img">저랑 다른 두 분도 같이 갔는데 실명이 적혀 있어서 인증 샷은 대표로 저만 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img">다다음주?!에 또 다른 행사를 준비하고 있으시다고 많은 관심 가져달라고 안내 받아서<br></div><div class="photo_img">열~심히 찾아가 보겠습니닷!</div><div class="photo_img"><br></div><div class="photo_img">다른 모임원 분들도 시간 되시면 같이 가요 &#39;-&#39;</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"> <div class="photo_img">#대전포스트잇#주말자유독서</div><div class="photo_img">#대전광역시 #희망의책대전본부#북토크 #중구문화동#한밭도서관</div><div class="photo_img">#우리의활보는사치가아니야#작가구르님#유튜버굴러라구르님#떼굴단</div> <br></div><div class="photo_img"><br></div><div class="photo_img"><br></div></div></div>', '2024-08-26 11:01:53');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('31ff2147-8b95-4bc2-a302-e0e11f6daa55', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 8/11 게임체인져:기본소득 북토크 참여 후기', '<div class="photo_img">오늘은 지난 번 &#39;독서모임 지원사업&#39;을 주관했던, 희망의책 대전본부가 진행하는 게임체인져:기본소득 작가님의 북토크를 다녀왔습니다 !</div><div class="photo_img"><br></div><div class="photo_img">북토크는 4시에 시작하는데 스튜디오 근처에서&nbsp;조금 빠른 2시 반에 모임원과 만나서 이야기를 하면서 ~ 빙수도 먹으면서 ~독서시간을 보냈습니다 ㅎ. ㅎ</div><div class="photo_img"><img src="http://localhost:8080/api/attachments/b2b226bc-afbd-4c56-a24b-408983fa6df1" data-image-index="0" alt="mosal4knrs.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/d5f651d6-d00a-4595-b93f-515896db1868" data-image-index="3" alt="mosaeKxNzC.png" width="257"><br></div><div class="photo_img"><div class="photo_img">책 들 중에는 독서동아리 지원사업으로 받은 &#39;우린 어쩌다 부부가 됐을까&#39; 책도 있었어요<br></div><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/c5939c29-e00e-4b5f-ac78-db86bce909be" data-image-index="1" alt="mosatZt85i.jpeg" width="257"><br></div><div class="photo_img">이번 북토크의 책 표지입니다.</div><div class="photo_img">그림이 뭔가 내용을 궁금하게 하는 요소들이 많아서 재밌는 그림이었어요.&nbsp;</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/6fafd50c-3d3a-4417-b537-f4d02972ddc7" data-image-index="2" alt="mosahLvFlk.jpeg" width="257"></div><div class="photo_img">희망의책 대전본부에서 공개한 스튜디오 내부 현장 사진입니다.</div><div class="photo_img">생각보다 다들 차려입고 오신 느낌이라 너무 후줄근하게 갔나... 하는 생각이 들었어요 ;ㅁ ;</div><div class="photo_img"><br></div><div class="photo_img">돌아가면서 소개도 하고 질문도 편하게 하면서 민감한 주제들이었지만 진행자 분이 말씀하셨던 &#39;비경쟁 토론&#39;을 지향하는 모습이 보여 즐겁게 2 시간 이었습니다 ㅋ. ㅋ</div><div class="photo_img"><br></div><div class="photo_img">그리고 8월 24일 토요일 오후 2시, 한밭도서관에서 대전 시민과 함께하는 같은 책 읽기 ?!를 한다고 들었는데 다음 행사도 기대감을 안고 마무리를 했습니다 ㅎ. ㅎ</div><div class="photo_img">다음 24일에 공지사항 올라올 때까지 즐겁게 기다려야겠습니다.</div><div class="photo_img"><br></div><div class="photo_img">#대전포스트잇#주말자유독서#어떻게들살고계십니까#우린어쩌다부부가됐을까</div><div class="photo_img">#대전광역시 #희망의책대전본부#북토크 #전민동#강스튜디오#게임체인저:기본소득#작가이선배</div><div class="photo_img"><br></div>', '2024-08-12 11:03:28');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('5b192d40-016f-4f75-a32b-183c8067aaf5', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 07/27 정모 후기', '<div class="photo_img">이번 달은 갑자기 내린 폭우로 날씨가 안 좋았는데 나와주신 모임원분들 모두 감사합니다~</div><div class="photo_img">모여서 근황토크를 시작으로 책 추천도 하면서 간단하게 대화 나눴습니다 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/ed2174e4-56ee-4ba4-9be9-960fdb011569" data-image-index="0" alt="mosaRoJhVa.jpeg" width="438"><br></div><div class="photo_img">7월은 다들 특히 바쁜 시간이었는지 각자 한 권씩 읽었습니다 ㅋ. ㅋ</div><div class="photo_img"><br></div><div class="photo_img"></div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/a1a129e6-da20-417b-a903-3a60fa511661" data-image-index="1" alt="mosaqd86RC.jpeg" width="438"><img src="http://localhost:8080/api/attachments/4529f9cc-34bd-4f32-92e1-29ff26a58097" data-image-index="2" alt="mosaaX2gre.jpeg" width="438"></div><div class="photo_img"> 오늘 간 곳은 대전 중구의 ABLE SPACE&nbsp; 1층 에이블 카페를 찾아갔는데 깔끔하고 조용한 카페였어요.<br></div><div class="photo_img"><br></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/5e1f8e0e-867b-4608-83c2-500a0b686cd7" data-image-index="3" alt="mosavqzaUt.jpeg" width="438">&nbsp; <img src="http://localhost:8080/api/attachments/de40ccc3-7775-42bc-b951-9ec1d7d8a383" data-image-index="4" alt="mosaNf1dGB.jpeg" width="438"> </div><div class="photo_img">안에 유료로 캔버스화를 그릴 수 있도록 아크릴화도 배치되어 있고 곳곳에 그림들이 전시되어 있고,&nbsp;주차장 한 켠에는 조그맣게 동물원을 만들어져 있어서 있었어요.</div><div class="photo_img">다음에는 그림을 그리러 와볼까 ?! 싶기도 하네요 ㅎㅎ</div><div class="photo_img"><br></div><div class="photo_img"><br></div><div class="photo_img"> #대전독서모임 #대전포스트잇 #문화동드로잉카페 #문화동카페에이블 #에이블스페이스<br></div></div>', '2024-07-28 11:55:44');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('692b0221-d854-4c65-8836-d3be834fc267', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 06/29 정모 후기', '<div class="photo_img">6월 마지막 주 토요일 ! 정모를 만년동에서 했습니다 ! ! !</div><div class="photo_img">날씨도 덥고~ 장마도 시작된다고 해서 우중충한 날씨에도 불구하고</div><div class="photo_img">모여주신 모임원 분들께 감사의 인사를 &#39;-&#39; b</div><div class="photo_img"><br></div><div class="photo_img">이번 달은 지난번 &#39;희망의책 대전본부&#39; 에서 지원 받은 책들을 가지고 진행했습니다!</div><div class="photo_img">지난 6월 동안 읽은 책들의 한 줄 평을 하면서 읽었던 책들을 정리해서 책꽂이 게시판에 업로드를 하고 마무리를 했습니다 &#39;-&#39; v</div><div class="photo_img"><img src="http://localhost:8080/api/attachments/d1082e20-651b-48f5-865d-4ab00933e6fc" data-image-index="0" alt="mosafdmDLA.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img"> 각자의 커피와 떡 와플을 같이 나온 아이스크림과 함께 나눠 먹으면서 얘기도 나누고 모임의 향후 계획을 공유 했습니다 ㅎ_ ㅎ</div><div class="photo_img"><img src="http://localhost:8080/api/attachments/13df880d-be99-4d75-86b7-0c842eb575a6" data-image-index="1" alt="mosa6O2nUn.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">정모를 마치고 이번 달은 &#39;제스모 공방&#39;을 다녀왔습니다~</div><div class="photo_img">이 곳은 원신흥동에 있는 A-rang Scent (아랑센트) ! ! !</div><div class="photo_img">처음 해보는거라 버벅였는데 친절하게 알려주셔서 쉽게 할 수 있었고 편한 분위기를 만들어주셔서 얘기도 나누면서 즐겁게 제작 했어요 :)</div><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/d4367a27-10f7-4dba-be83-a70d24b6c432" data-image-index="2" alt="mosayjBgo1.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">같이 갔던 분은 지난번 제스모 공방에 참여해서 금방금방 하셔서 남는 시간에 인형도 만들었답니다 ㅎ. ㅎ</div><div class="photo_img"><img src="http://localhost:8080/api/attachments/be03cc8a-ea19-4618-bc7e-0b488a0ffc0e" data-image-index="3" alt="mosaVn7E2b.jpeg" width="257"></div><div class="photo_img"><img src="http://localhost:8080/api/attachments/0ce97d52-9354-4cbd-a2ac-23fc5c18d918" data-image-index="4" alt="mosaPg4jFT.jpeg" width="257"></div><br></div><div class="photo_img">#대전독서모임 #대전포스트잇 #만년동새삶스레 #원신흥동아랑센트</div><div class="photo_img"></div>', '2024-06-29 21:48:45');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('8cab097d-980a-48e4-bddd-d3c34e7f2bfc', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 6/25 자유독서모임 후기', '이번 자유 독서 시간에는 책책님과 함께<div class="photo_img">지난 달 &#39;희망의책 대전본부&#39; 지원사업</div><div class="photo_img">선정되어 받은 책을 먼저 읽기 시작했습니다!!</div><div class="photo_img"><br></div><div class="photo_img">아직 못 받으신 분들은 다음 자유 독서 때나</div><div class="photo_img">이번 6월 정모 때 드릴게요 ㅎ. ㅎ</div><div class="photo_img"><br></div><div class="photo_img"><div class="photo_img"><div class="photo_img"><img src="http://localhost:8080/api/attachments/82a41db0-268a-418c-915c-f22083a5b538" data-image-index="0" alt="mosaNo4Wo5.jpeg" width="257"></div><div class="photo_img"><br></div><div class="photo_img">#하얀책상_한남대점</div><br></div><br></div>', '2024-06-26 12:52:55');
INSERT INTO tb_article (id, version, exposed, fixed, type, category_id, created_by, title, content, created_date) VALUES ('4fd98a86-e42c-49f9-b3c1-07eb8a042c77', 0, true, false, 'HTML', 'ddd290c0-1e1f-401b-998e-2b1921a324ca', 'yasha_bread', '[대전포스트잇] 6/18 자유독서모임 후기', '오랜만의 독서 타임이라 반가워서<div class="photo_img">단체 사진찍는 것두 까먹었네요 ㅠ</div><div class="photo_img">아쉽게나마 단독샷이라도...&nbsp;<br><div class="photo_img"><img src="http://localhost:8080/api/attachments/30dc1cb7-4c11-4d15-a566-2b0b2feb2153" data-image-index="0" alt="mosaDMZflc.jpeg" width="257"></div></div>', '2024-06-18 22:27:52');
