INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('bb3d28f2-25f0-4a42-ad67-42fa31d742c0', 0, true, 'c080cdd1-4cd0-4fcc-85d9-57bd99f219b3', 'yasha_bread', '역사를 다루는 소설중에 또 읽을만한 책이 숨어있었군요 ㅎ. ㅎ', '2024-11-17 22:33:57');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('daf235c6-5f09-4c59-9fb4-83d37e959991', 0, true, 'f00d497f-feec-49a6-b0f0-95863e9e97c8', 'yasha_bread', '자본주의를 이해하는데 좋은책이네요 ㅎ. ㅎ 역시 ebs인가 ㅎㅎ', '2024-11-20 10:51:29');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('f8df932f-374c-4be3-bc7e-ba75635538ee', 0, true, 'f00d497f-feec-49a6-b0f0-95863e9e97c8', 'hwanggiumin', '댓글이당 이맛에 책꽂이 씁니다', '2024-11-20 10:52:18');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('d5026df1-2b8d-422d-a340-a1192aa90b98', 0, true, '842b0e51-26c7-4289-bb77-815375ea3595', 'yasha_bread', '인생 공식은 참신한 느낌이네요 ㅎㅎ 읽어보지 않아서 딴소리일 수 있지만, 인생 = 능력(재능) x 사고방식 x (인적 물적 자본 + 열의) 가 더 정확하지않을까 싶은 생각도 드네요 ㅎㅎ', '2024-11-20 10:56:50');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('d1965611-05c6-41c6-8282-db7f5e900161', 0, true, '842b0e51-26c7-4289-bb77-815375ea3595', 'hwanggiumin', '능력과 사고방식은 개인에 문제지만 열의 라는게 말그대로 들어가는 노력이라고 할수 있으니까 인적 물적 자본(일을 원활하게 진행 할수 있도록 하는 회사에 도움.직원들의 도움) 에 개인에 노력을 더하는게 훨씬 맞는 말이긴 하네요 일은 혼자 한다고 생각할수 있지만 인생은 혼자 살수 없으니까요', '2024-11-20 11:04:02');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('c39b5e04-9953-425d-9bf8-8da28bd909aa', 0, true, '842b0e51-26c7-4289-bb77-815375ea3595', 'yhg1803', 'ㅎ_ㅎ 돈을 벌기 위하여...', '2024-11-20 11:04:20');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('24cd12fe-bfd8-4f16-80a8-b39c1ba7c079', 0, true, '842b0e51-26c7-4289-bb77-815375ea3595', 'hwanggiumin', '이 책은 무려 내가 돈때문에 일하는거라면 하지 않겠다는 문장이 나옵니다. 실제로 다른 사업을 하고 싶다고 일을 진행 하며 내가 이걸 돈떄문에 하는건지 오랫동안 스스로에게 질문을 했다는 내용이 있습니다. 허허허', '2024-11-20 11:05:42');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('f1ef7504-d476-41d1-be89-ba451b67fcfd', 0, true, '842b0e51-26c7-4289-bb77-815375ea3595', '4643one', '책을 읽은 것만 같은 그런 기분, 덕분에 오늘의 독서 한권(왜 일하는가) 추가 완료!', '2024-11-20 11:09:55');
