INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('8f5476c6-3466-441e-8130-fd55a0b8d532', 0, true, 'df56b762-2f31-405c-bbba-4ea3159ff3c9', 'yasha_bread', '오 흥미진진한 내용이네여 ㅇ0 ㅇ 저장해놔야겟다', '2024-11-30 18:22:47');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('be7499da-1190-4046-a05c-0bbf63812235', 0, true, 'df56b762-2f31-405c-bbba-4ea3159ff3c9', 'dbsthd81', '청소년 소설로 나온 터라, 읽는 데 걸리는 시간이 짧기 때문에 킬링타임용으로도 좋아요!', '2024-12-01 14:57:13');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('e5802f58-f076-4e2b-ad16-c607eada91b3', 0, true, 'a3d209b3-c8a6-4e81-b028-5122ec966de8', 'yasha_bread', '책 이름은 많이 들어봤었어서 읽어볼까 싶다가도 내용이 지독하다니까 또 거리두기 해야될 것 같은 느낌이네여 ㅋㅋㅋ', '2024-11-30 18:24:41');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('17c7fd7d-1a83-43f1-ad11-2ee907dc8eef', 0, true, 'a3d209b3-c8a6-4e81-b028-5122ec966de8', 'dbsthd81', '내용이 지독해요. 사람 대 사람으로서 보면 왜 저러고 사나 싶은 내용이 있지만, 어떤 시대를 살아가는 특정 성향의 사람들을 대표하는 거라 생각하고 보면 또 봐줄만해요', '2024-12-01 14:58:01');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('12107ee7-7f82-4136-96d2-ca1eeaa6638c', 0, true, 'a3d209b3-c8a6-4e81-b028-5122ec966de8', 'yhg1803', '다른 소설에서 많이 언급돼서 제목만 들어보았는데 그런 내용이군요', '2024-12-07 11:17:43');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('e28f1385-d62d-4f62-a975-99747f21b475', 0, true, 'd94c07b6-a5b7-460c-b751-2da02cab6564', 'yasha_bread', '왠지 사소한 것들이라고 했지만 읽어보면 전혀 사소한 것이 아닐것 같은 느낌이 드네요 ㅠ 벌써부터 살짝 울적..', '2024-12-01 12:15:47');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('82d444d0-fd00-467f-ab36-b93d1d2122c8', 0, true, 'd94c07b6-a5b7-460c-b751-2da02cab6564', 'yhg1803', '사소한게 알고보면 소중한법', '2024-12-07 11:15:59');
INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('3d7869cd-ce86-49b0-bce7-ad9597373ec2', 0, true, 'baa066f3-7b61-4e4a-8842-c737fab434cb', 'yasha_bread', '한 때 핫했던 게임과몰입에 대한 내용처럼 보이네요 ㅇ0 ㅇ', '2024-12-01 22:01:01');
