INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('1199b7ce-5501-4314-8daa-ee000dc3bec6', 0, true, '568ba79f-a5bc-468c-9ff0-98760b091804', 'yasha_bread', '사건이 일어나고 있는 시간대를 파악해서 읽어야 한다는 점 이 부분이 뭔가 영화로치면 플래시백?! 같은 느낌 이려나요 ㅎㅎ', '2024-12-20 20:17:46');
