INSERT INTO tb_reply (id, version, exposed, article_id, created_by, content, created_date) VALUES ('e39f90d2-f208-4869-8d1c-dd995121f9df', 0, true, 'ca162e1d-0701-4676-8811-9c66dbc02719', 'yasha_bread', '지금 읽고 있는데 너무너무너무 기대되는 후기네요 ㅎㅎㅎ', '2024-12-26 20:02:03');
